{
  "name": "Road Trip Pro",
  "description": "An AI-powered assistant for planning multi-city professional journeys, optimizing for profitable stops and logical routing."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum TravelMode {
  Car = 'Car',
  Bus = 'Bus',
  Plane = 'Plane',
  Mixed = 'Mixed'
}

export interface Stop {
  city: string;
  day: number;
  description: string;
  demandScore: number; // 0-100
  travelToNext: string;
  activity: string;
  coordinates?: {
    lat: number;
    lng: number;
  };
}

export interface Itinerary {
  routeName: string;
  totalDistance: string;
  totalDuration: string;
  stops: Stop[];
  summary: string;
}

export interface TripFormData {
  origin: string;
  destination: string;
  startDate: string;
  endDate: string;
  mandatoryStops: string[];
  numberOfStops: number;
  travelMode: TravelMode;
}

import { TravelMode } from './types';

export const DEFAULT_FORM_DATA = {
  origin: 'New York, NY',
  destination: 'Los Angeles, CA',
  startDate: '',
  endDate: '',
  mandatoryStops: ['Chicago, IL', 'Denver, CO'],
  numberOfStops: 4,
  travelMode: TravelMode.Car,
};

export const GEMINI_MODEL = 'gemini-3-flash-preview';

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { TripFormData, Itinerary } from "../types";
import { GEMINI_MODEL } from "../constants";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

const itinerarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    routeName: { type: Type.STRING, description: "A catchy name for this route" },
    totalDistance: { type: Type.STRING, description: "Estimated total distance" },
    totalDuration: { type: Type.STRING, description: "Estimated total travel duration" },
    summary: { type: Type.STRING, description: "A brief summary of why this route is profitable/good" },
    stops: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day: { type: Type.INTEGER },
          city: { type: Type.STRING },
          description: { type: Type.STRING, description: "Why this stop is profitable or strategic" },
          demandScore: { type: Type.INTEGER, description: "Market demand score 0-100" },
          travelToNext: { type: Type.STRING, description: "Time to next stop or destination" },
          activity: { type: Type.STRING, description: "Recommended professional/business activity" },
        },
        required: ["day", "city", "description", "demandScore", "travelToNext", "activity"],
      },
    },
  },
  required: ["routeName", "totalDistance", "totalDuration", "stops", "summary"],
};

export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();

  const prompt = `
    Act as an expert travel logistician for professionals.
    Plan a road trip from ${data.origin} to ${data.destination}.

    Parameters:
    - Mode: ${data.travelMode}
    - Mandatory stops: ${data.mandatoryStops.join(', ')} (Must be included and logically sequenced).
    - Total overnight stops desired: ${data.numberOfStops} (You can add high-opportunity cities to fill the gaps).
    - Dates: ${data.startDate || 'Not specified'} to ${data.endDate || 'Not specified'}.

    Goal:
    - Transform travel into opportunity.
    - Suggest stops in cities with good market demand (business, gigs, networking).
    - Logically sequence the route.
    ${isAlternative ? 'Provide a DIFFERENT route than the most obvious one, exploring alternative cities.' : 'Provide the most optimal and profitable route.'}

    Output JSON with the following structure:
    - routeName, totalDistance, totalDuration, summary
    - stops: Array of objects with day, city, description (reason for stop), demandScore (0-100), travelToNext, activity.
  `;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as Itinerary;
  } catch (error) {
    console.error("Error generating itinerary:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { Plus, X, MapPin, Calendar, Briefcase, Settings } from 'lucide-react';
import { TripFormData, TravelMode } from '../types';

interface InputFormProps {
  initialData: TripFormData;
  onSubmit: (data: TripFormData, isAlternative: boolean) => void;
  isLoading: boolean;
}

export const InputForm: React.FC<InputFormProps> = ({ initialData, onSubmit, isLoading }) => {
  const [formData, setFormData] = useState<TripFormData>(initialData);

  const handleChange = (field: keyof TripFormData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleStopChange = (index: number, value: string) => {
    const newStops = [...formData.mandatoryStops];
    newStops[index] = value;
    handleChange('mandatoryStops', newStops);
  };

  const addStop = () => {
    handleChange('mandatoryStops', [...formData.mandatoryStops, '']);
  };

  const removeStop = (index: number) => {
    const newStops = formData.mandatoryStops.filter((_, i) => i !== index);
    handleChange('mandatoryStops', newStops);
  };

  return (
    <div className="bg-gray-800 p-6 rounded-xl shadow-lg border border-gray-700 h-full overflow-y-auto">
      <h2 className="text-2xl font-bold text-white mb-6 flex items-center gap-2">
        <Settings className="w-6 h-6 text-blue-400" />
        Configuration
      </h2>

      <div className="space-y-5">
        {/* Origin & Destination */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-400 mb-1">Origin</label>
            <div className="relative">
              <MapPin className="absolute left-3 top-3 w-4 h-4 text-gray-500" />
              <input
                type="text"
                value={formData.origin}
                onChange={(e) => handleChange('origin', e.target.value)}
                className="w-full bg-gray-900 border border-gray-600 rounded-lg py-2.5 pl-10 pr-4 text-white placeholder-gray-500 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                placeholder="Start City"
              />
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-400 mb-1">Destination</label>
            <div className="relative">
              <MapPin className="absolute left-3 top-3 w-4 h-4 text-gray-500" />
              <input
                type="text"
                value={formData.destination}
                onChange={(e) => handleChange('destination', e.target.value)}
                className="w-full bg-gray-900 border border-gray-600 rounded-lg py-2.5 pl-10 pr-4 text-white placeholder-gray-500 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                placeholder="End City"
              />
            </div>
          </div>
        </div>

        {/* Dates */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-400 mb-1">Departure (Optional)</label>
            <div className="relative">
              <Calendar className="absolute left-3 top-3 w-4 h-4 text-gray-500" />
              <input
                type="date"
                value={formData.startDate}
                onChange={(e) => handleChange('startDate', e.target.value)}
                className="w-full bg-gray-900 border border-gray-600 rounded-lg py-2.5 pl-10 pr-4 text-white placeholder-gray-500 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all [color-scheme:dark]"
              />
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-400 mb-1">Return (Optional)</label>
            <div className="relative">
              <Calendar className="absolute left-3 top-3 w-4 h-4 text-gray-500" />
              <input
                type="date"
                value={formData.endDate}
                onChange={(e) => handleChange('endDate', e.target.value)}
                className="w-full bg-gray-900 border border-gray-600 rounded-lg py-2.5 pl-10 pr-4 text-white placeholder-gray-500 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all [color-scheme:dark]"
              />
            </div>
          </div>
        </div>

        {/* Mandatory Stops */}
        <div>
          <label className="block text-sm font-medium text-gray-400 mb-2">Mandatory Stops</label>
          <div className="space-y-2">
            {formData.mandatoryStops.map((stop, index) => (
              <div key={index} className="flex gap-2">
                <input
                  type="text"
                  value={stop}
                  onChange={(e) => handleStopChange(index, e.target.value)}
                  className="flex-1 bg-gray-900 border border-gray-600 rounded-lg py-2 px-4 text-white focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="City to visit"
                />
                <button
                  onClick={() => removeStop(index)}
                  className="p-2 text-gray-400 hover:text-red-400 hover:bg-gray-700 rounded-lg transition-colors"
                  aria-label="Remove stop"
                >
                  <X className="w-5 h-5" />
                </button>
              </div>
            ))}
            <button
              onClick={addStop}
              className="flex items-center gap-2 text-sm text-blue-400 hover:text-blue-300 font-medium mt-2 px-2 py-1 rounded hover:bg-gray-700/50 transition-colors w-fit"
            >
              <Plus className="w-4 h-4" /> Add Stop
            </button>
          </div>
        </div>

        {/* Settings */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-400 mb-1">Total Stops</label>
            <input
              type="number"
              min={1}
              max={20}
              value={formData.numberOfStops}
              onChange={(e) => handleChange('numberOfStops', parseInt(e.target.value))}
              className="w-full bg-gray-900 border border-gray-600 rounded-lg py-2.5 px-4 text-white focus:ring-2 focus:ring-blue-500 outline-none"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-400 mb-1">Travel Mode</label>
            <div className="relative">
              <Briefcase className="absolute left-3 top-3 w-4 h-4 text-gray-500" />
              <select
                value={formData.travelMode}
                onChange={(e) => handleChange('travelMode', e.target.value)}
                className="w-full bg-gray-900 border border-gray-600 rounded-lg py-2.5 pl-10 pr-4 text-white focus:ring-2 focus:ring-blue-500 outline-none appearance-none"
              >
                {Object.values(TravelMode).map(mode => (
                  <option key={mode} value={mode}>{mode}</option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* Buttons */}
        <div className="pt-4 flex flex-col gap-3">
          <button
            onClick={() => onSubmit(formData, false)}
            disabled={isLoading}
            className={`w-full py-3 px-4 rounded-lg font-bold text-white shadow-lg transition-all transform hover:scale-[1.02] active:scale-[0.98] ${
              isLoading 
                ? 'bg-gray-600 cursor-not-allowed' 
                : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 shadow-blue-500/25'
            }`}
          >
            {isLoading ? 'Generating Plan...' : 'Generate Itinerary'}
          </button>

          <button
            onClick={() => onSubmit(formData, true)}
            disabled={isLoading}
            className="w-full py-3 px-4 rounded-lg font-bold text-gray-300 bg-gray-700 border border-gray-600 hover:bg-gray-600 hover:text-white transition-all"
          >
             Generate Alternative
          </button>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Cell
} from 'recharts';
import { Stop } from '../types';

interface DemandChartProps {
  stops: Stop[];
}

const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-gray-800 border border-gray-700 p-3 rounded-lg shadow-xl">
        <p className="font-bold text-white mb-1">{label}</p>
        <p className="text-blue-400 text-sm">
          Demand Score: <span className="font-mono font-bold text-white">{payload[0].value}</span>
        </p>
        <p className="text-gray-400 text-xs mt-1 italic">
            {payload[0].payload.activity}
        </p>
      </div>
    );
  }
  return null;
};

export const DemandChart: React.FC<DemandChartProps> = ({ stops }) => {
  const data = stops.map(stop => ({
    name: stop.city.split(',')[0], // Shorten name
    score: stop.demandScore,
    fullCity: stop.city,
    activity: stop.activity
  }));

  return (
    <div className="w-full h-64 bg-gray-800/50 rounded-xl border border-gray-700 p-4">
      <h3 className="text-sm font-semibold text-gray-400 mb-4 uppercase tracking-wider">Market Demand Analysis</h3>
      <ResponsiveContainer width="100%" height="100%">
        <BarChart
          data={data}
          margin={{ top: 5, right: 30, left: 0, bottom: 5 }}
        >
          <CartesianGrid strokeDasharray="3 3" stroke="#374151" vertical={false} />
          <XAxis 
            dataKey="name" 
            stroke="#9ca3af" 
            tick={{ fill: '#9ca3af', fontSize: 12 }}
            axisLine={{ stroke: '#4b5563' }}
            tickLine={false}
          />
          <YAxis 
            stroke="#9ca3af"
            tick={{ fill: '#9ca3af', fontSize: 12 }}
            axisLine={{ stroke: '#4b5563' }}
            tickLine={false}
          />
          <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(255, 255, 255, 0.05)' }} />
          <Bar dataKey="score" radius={[4, 4, 0, 0]}>
            {data.map((entry, index) => (
              <Cell 
                key={`cell-${index}`} 
                fill={entry.score > 80 ? '#3b82f6' : entry.score > 50 ? '#6366f1' : '#8b5cf6'} 
              />
            ))}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

import React from 'react';
import { Itinerary, Stop } from '../types';
import { Map, Clock, TrendingUp, Navigation, Star } from 'lucide-react';
import { DemandChart } from './DemandChart';

interface ItineraryDisplayProps {
  itinerary: Itinerary | null;
}

export const ItineraryDisplay: React.FC<ItineraryDisplayProps> = ({ itinerary }) => {
  if (!itinerary) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-8 text-gray-500">
        <Map className="w-16 h-16 mb-4 opacity-20" />
        <h3 className="text-xl font-medium mb-2">Ready to Plan</h3>
        <p className="max-w-md">Enter your trip details on the left and click "Generate Itinerary" to see your AI-optimized professional road trip.</p>
      </div>
    );
  }

  return (
    <div className="h-full overflow-y-auto pr-2 space-y-6">
      {/* Header Summary */}
      <div className="bg-gradient-to-br from-gray-800 to-gray-900 p-6 rounded-xl border border-gray-700 shadow-lg relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-10">
          <Map className="w-32 h-32 text-white" />
        </div>
        <div className="relative z-10">
          <h2 className="text-3xl font-bold text-white mb-2">{itinerary.routeName}</h2>
          <p className="text-gray-300 mb-4 text-lg leading-relaxed">{itinerary.summary}</p>

          <div className="flex flex-wrap gap-4 mt-4">
