      {/* Demand Chart */}
      <DemandChart stops={itinerary.stops} />

      {/* Timeline */}
      <div className="relative pl-8 border-l-2 border-gray-700 ml-4 space-y-8 pb-10">
        {itinerary.stops.map((stop, index) => (
          <div key={index} className="relative">
            {/* Timeline Dot */}
            <div className={`absolute -left-[41px] top-0 w-6 h-6 rounded-full border-4 border-gray-900 ${
              index === 0 ? 'bg-green-500' : index === itinerary.stops.length - 1 ? 'bg-red-500' : 'bg-blue-500'
            } shadow-[0_0_0_4px_rgba(59,130,246,0.1)]`}></div>

            <div className="bg-gray-800 rounded-lg p-5 border border-gray-700 shadow-md hover:border-gray-600 transition-colors group">
              <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4 mb-3">
                <div>
                  <div className="flex items-center gap-3 mb-1">
                    <span className="bg-gray-700 text-gray-300 text-xs font-bold px-2 py-0.5 rounded uppercase tracking-wide">
                      Day {stop.day}
                    </span>
                    <h3 className="text-xl font-bold text-white">{stop.city}</h3>
                  </div>
                  <div className="flex items-center gap-2 text-sm text-blue-400">
                     <TrendingUp className="w-4 h-4" />
                     <span>Market Opportunity: {stop.activity}</span>
                  </div>
                </div>

                <div className="flex items-center gap-2 bg-gray-900/50 px-3 py-1.5 rounded border border-gray-700 self-start">
                   <div className="text-xs text-gray-400 uppercase font-bold mr-1">Demand</div>
                   <div className={`text-lg font-bold ${
                     stop.demandScore > 80 ? 'text-green-400' : stop.demandScore > 50 ? 'text-yellow-400' : 'text-gray-400'
                   }`}>{stop.demandScore}</div>
                </div>
              </div>

              <p className="text-gray-300 text-sm leading-relaxed mb-4 border-l-2 border-gray-600 pl-3">
                {stop.description}
              </p>

              {index < itinerary.stops.length - 1 && (
                <div className="flex items-center gap-2 text-xs text-gray-500 mt-4 pt-3 border-t border-gray-700/50">
                   <Navigation className="w-3 h-3" />
                   <span>Travel to next: {stop.travelToNext}</span>
                </div>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { InputForm } from './components/InputForm';
import { ItineraryDisplay } from './components/ItineraryDisplay';
import { TripFormData, Itinerary } from './types';
import { DEFAULT_FORM_DATA } from './constants';
import { generateItinerary } from './services/geminiService';
import { Car } from 'lucide-react';

const App: React.FC = () => {
  const [itinerary, setItinerary] = useState<Itinerary | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async (data: TripFormData, isAlternative: boolean) => {
    setIsLoading(true);
    setError(null);
    try {
      const result = await generateItinerary(data, isAlternative);
      setItinerary(result);
    } catch (err: any) {
      setError(err.message || "Failed to generate itinerary. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-900 text-gray-100 font-sans selection:bg-blue-500/30">
      {/* Navbar */}
      <header className="flex-none bg-gray-800 border-b border-gray-700 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-gradient-to-tr from-blue-600 to-indigo-600 p-2 rounded-lg shadow-lg shadow-blue-500/20">
              <Car className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-gray-400">
              Road Trip Pro
            </h1>
          </div>
          <div className="text-sm text-gray-400 hidden sm:block">
            Professional Itinerary Planner
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-hidden">
        <div className="max-w-7xl mx-auto h-full p-4 sm:p-6 lg:p-8 flex flex-col lg:flex-row gap-6">

          {/* Left Panel: Inputs */}
          <div className="w-full lg:w-1/3 flex-none h-full overflow-hidden flex flex-col">
            <InputForm 
              initialData={DEFAULT_FORM_DATA} 
              onSubmit={handleGenerate}
              isLoading={isLoading}
            />
            {error && (
              <div className="mt-4 p-4 bg-red-900/50 border border-red-700/50 rounded-lg text-red-200 text-sm">
                {error}
              </div>
            )}
          </div>

          {/* Right Panel: Display */}
          <div className="flex-1 h-full overflow-hidden bg-gray-900/50 rounded-xl relative">
            <ItineraryDisplay itinerary={itinerary} />

            {/* Loading Overlay */}
            {isLoading && (
              <div className="absolute inset-0 bg-gray-900/80 backdrop-blur-sm z-10 flex flex-col items-center justify-center">
                <div className="relative w-20 h-20 mb-4">
                  <div className="absolute inset-0 border-t-4 border-blue-500 border-solid rounded-full animate-spin"></div>
                  <div className="absolute inset-2 border-t-4 border-indigo-500 border-solid rounded-full animate-spin [animation-direction:reverse]"></div>
                </div>
                <p className="text-blue-400 font-medium animate-pulse">Analyzing routes & market data...</p>
              </div>
            )}
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

export enum TravelMode {
  Car = 'Car',
  Bus = 'Bus',
  Plane = 'Plane',
  Mixed = 'Mixed'
}

export interface Stop {
  city: string;
  day: number;
  description: string;
  demandScore: number; // 0-100
  travelToNext: string;
  activity: string;
  nightsToStay: number;
  coordinates?: {
    lat: number;
    lng: number;
  };
}

export interface Itinerary {
  routeName: string;
  totalDistance: string;
  totalDuration: string;
  stops: Stop[];
  summary: string;
}

export interface TripFormData {
  origin: string;
  destination: string;
  startDate: string;
  endDate: string;
  mandatoryStops: string[];
  numberOfStops: number;
  travelMode: TravelMode;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
