      },
    },
  },
  required: ["routeName", "totalDistance", "totalDuration", "stops", "summary"],
};

export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();

  const prompt = `
    Act as an expert travel logistician for a professional Male Massage Therapist targeting the LGBTQ+ market.
    Plan a road trip from ${data.origin} to ${data.destination}.

    Parameters:
    - Mode: ${data.travelMode}
    - Mandatory stops: ${data.mandatoryStops.join(', ')} (Must be included and logically sequenced).
    - Total overnight stops desired: ${data.numberOfStops} (Add high-opportunity cities to fill gaps).
    - Dates: ${data.startDate || 'Not specified'} to ${data.endDate || 'Not specified'}.

    ${KEYWORD_MARKET_DATA}

    Goal:
    - Transform travel into opportunity.
    - Suggest stops in cities with HIGH DEMAND for the keywords provided.
    - Logically sequence the route.
    - Recommend 'nightsToStay' for each city. 
      * Large metros with high gay population/search volume (e.g., NY, LA, Chicago, Dallas, Atlanta, Miami) = 3-5 nights.
      * Mid-sized cities with active communities = 1-2 nights.

    ${isAlternative ? 'Provide a DIFFERENT route than the most obvious one, exploring alternative cities.' : 'Provide the most optimal and profitable route.'}

    Output JSON with the following structure:
    - routeName, totalDistance, totalDuration, summary
    - stops: Array of objects with day (cumulative), city, description, demandScore, nightsToStay, travelToNext, activity.
  `;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as Itinerary;
  } catch (error) {
    console.error("Error generating itinerary:", error);
    throw error;
  }
};

