interface InputFormProps {
  initialData: TripFormData;
  onSubmit: (data: TripFormData, isAlternative: boolean) => void;
  isLoading: boolean;
}

export const InputForm: React.FC<InputFormProps> = ({ initialData, onSubmit, isLoading }) => {
  const [formData, setFormData] = useState<TripFormData>(initialData);

  const handleChange = (field: keyof TripFormData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleStopChange = (index: number, field: keyof MandatoryStop, value: string) => {
    const newStops = [...formData.mandatoryStops];
    newStops[index] = { ...newStops[index], [field]: value };
    handleChange('mandatoryStops', newStops);
  };

  const addStop = () => {
    handleChange('mandatoryStops', [...formData.mandatoryStops, { location: '', date: '' }]);
  };

  const removeStop = (index: number) => {
    const newStops = formData.mandatoryStops.filter((_, i) => i !== index);
    handleChange('mandatoryStops', newStops);
  };

  return (
    <div className="bg-gray-800 p-6 rounded-xl shadow-lg border border-gray-700 h-full overflow-y-auto">
      <h2 className="text-2xl font-bold text-white mb-6 flex items-center gap-2">
