import { GoogleGenAI, Type, Schema } from "@google/genai";
import { TripFormData, Itinerary } from "../types";
import { GEMINI_MODEL } from "../constants";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

const KEYWORD_MARKET_DATA = `
MARKET DEMAND CONTEXT (Monthly Search Volumes - Jan 2026):
Use this data to determine demand scores and recommended nights to stay. Higher relevance to these terms in a city means longer stay.
1. gay massage - 450,000
