const itinerarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    routeName: { type: Type.STRING, description: "A catchy name for this route" },
    totalDistance: { type: Type.STRING, description: "Estimated total distance" },
    totalDuration: { type: Type.STRING, description: "Estimated total travel duration including stay nights" },
    summary: { type: Type.STRING, description: "A brief summary of why this route is profitable/good" },
    stops: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day: { type: Type.INTEGER },
          city: { type: Type.STRING },
          description: { type: Type.STRING, description: "Why this stop is profitable or strategic" },
          demandScore: { type: Type.INTEGER, description: "Market demand score 0-100 based on the provided keywords" },
          nightsToStay: { type: Type.INTEGER, description: "Recommended nights to stay based on strict scoring logic" },
          travelToNext: { type: Type.STRING, description: "Time to next stop or destination" },
          activity: { type: Type.STRING, description: "Recommended professional/business activity matching the keywords" },
          coordinates: {
             type: Type.OBJECT,
             properties: {
                lat: { type: Type.NUMBER },
                lng: { type: Type.NUMBER }
             }
          }
        },
        required: ["day", "city", "description", "demandScore", "nightsToStay", "travelToNext", "activity"],
      },
    },
  },
  required: ["routeName", "totalDistance", "totalDuration", "stops", "summary"],
};

export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();

  const mandatoryStopsText = data.mandatoryStops
    .map(s => {
      let info = s.location;
      if (s.date) info += ` (Target Date: ${s.date})`;
      if (s.nights) info += ` (Stay: ${s.nights} nights)`;
      return info;
    })
    .join(', ');

  const destinationText = data.destinationDate 
    ? `${data.destination} (Target Arrival: ${data.destinationDate})` 
    : data.destination;

  const prompt = `
    Act as an expert travel logistician for a professional Male Massage Therapist targeting the LGBTQ+ market.
    Plan a road trip from ${data.origin} to ${destinationText}.

    Parameters:
    - Mode: ${data.travelMode}
    - Max Driving Per Day: ${data.maxDriveHours} hours (CRITICAL: ensure travel time between overnight stops does NOT exceed this significantly).
    - Mandatory stops: ${mandatoryStopsText} (Must be included and logically sequenced).
    - Dates: ${data.startDate || 'Not specified'} to ${data.endDate || 'Not specified'}.

    ${KEYWORD_MARKET_DATA}

    STRICT STOP CLASSIFICATION & DURATION LOGIC:
    You must calculate a 'Demand Score' (0-100) for each potential city based on the search volume keywords.
    Apply these exact rules for 'nightsToStay':

    1. Score < 40: ❌ DO NOT STOP. (Skip city unless it is a Mandatory Stop or strictly required for logistics).
    2. Score 40-59: ✅ 1 Night. (Low demand, stop only if convenient/on-route).
    3. Score 60-84: ✅ 2 Nights. (Mid demand).
    4. Score >= 85: ✅ 3 Nights. (High demand / Spike zone).

    SAFETY RULE: Even if Score > 40, DO NOT stop if the local search volume is < 500/month or the city is significantly off-route.

    Goal:
    - Transform travel into opportunity.
    - Logically sequence the route.
    - Provide approximate lat/lng coordinates for each city.

    ${isAlternative ? 'Provide a DIFFERENT route than the most obvious one, exploring alternative cities.' : 'Provide the most optimal and profitable route.'}

    Output JSON with the following structure:
    - routeName, totalDistance, totalDuration, summary
    - stops: Array of objects with day (cumulative), city, description, demandScore, nightsToStay, travelToNext, activity, coordinates {lat, lng}.
  `;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const result = JSON.parse(text) as Itinerary;

    // Attach the start date and mode from input to the result so the display component can use it
    if (data.startDate) {
        result.startDate = data.startDate;
    }
    result.travelMode = data.travelMode;

    return result;
  } catch (error) {
    console.error("Error generating itinerary:", error);
    throw error;
  }
};

import React, { useState } from 'react';
