interface ItineraryDisplayProps {
  itinerary: Itinerary | null;
}

export const ItineraryDisplay: React.FC<ItineraryDisplayProps> = ({ itinerary }) => {
  const [expandedStopIndex, setExpandedStopIndex] = useState<number | null>(null);

  if (!itinerary) {
