      </div>
    );
  }

  const toggleExpand = (index: number) => {
    setExpandedStopIndex(expandedStopIndex === index ? null : index);
  };

  const getExactDate = (dayOffset: number): string | null => {
    if (!itinerary.startDate) return null;
    const date = new Date(itinerary.startDate);
    // Add days. Note: Stop Day 1 = Start Date.
    date.setDate(date.getDate() + (dayOffset - 1)); 
    // Format: "Mon, Jan 15"
    return date.toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric' });
  };

  const getModeIcon = (mode: string | undefined) => {
    const normalizeMode = mode?.toLowerCase() || '';
    if (normalizeMode.includes('car')) return <Car className="w-5 h-5 text-blue-400" />;
    if (normalizeMode.includes('bus')) return <Bus className="w-5 h-5 text-blue-400" />;
    if (normalizeMode.includes('plane') || normalizeMode.includes('flight')) return <Plane className="w-5 h-5 text-blue-400" />;
    if (normalizeMode.includes('mixed')) return <Shuffle className="w-5 h-5 text-blue-400" />;
    return <Navigation className="w-5 h-5 text-blue-400" />;
  };

  return (
    <div className="h-full overflow-y-auto pr-2 space-y-6">
