            <div className="flex items-center gap-2 bg-gray-700/50 px-3 py-1.5 rounded-lg border border-gray-600">
              <span className="text-blue-400">{getModeIcon(itinerary.travelMode)}</span>
              <span className="text-gray-200 text-sm font-medium">{itinerary.totalDistance}</span>
            </div>
            <div className="flex items-center gap-2 bg-gray-700/50 px-3 py-1.5 rounded-lg border border-gray-600">
              <Clock className="w-4 h-4 text-indigo-400" />
              <span className="text-gray-200 text-sm font-medium">{itinerary.totalDuration}</span>
            </div>
             <div className="flex items-center gap-2 bg-gray-700/50 px-3 py-1.5 rounded-lg border border-gray-600">
              <Star className="w-4 h-4 text-yellow-400" />
              <span className="text-gray-200 text-sm font-medium">{itinerary.stops.length} Stops</span>
            </div>
          </div>
        </div>
      </div>

      {/* Demand Chart */}
      <DemandChart stops={itinerary.stops} />

      {/* Timeline */}
      <div className="relative pl-8 border-l-2 border-gray-700 ml-4 space-y-8 pb-10">
        {itinerary.stops.map((stop, index) => {
          const isExpanded = expandedStopIndex === index;
          const exactDate = getExactDate(stop.day);

          // Determine the icon for this specific leg of the journey, defaulting to itinerary mode
          const legIcon = getModeIcon(stop.transportMode || itinerary.travelMode);

          return (
            <div key={index} className="relative">
              {/* Timeline Dot */}
              <div className={`absolute -left-[41px] top-6 w-6 h-6 rounded-full border-4 border-gray-900 ${
                index === 0 ? 'bg-green-500' : index === itinerary.stops.length - 1 ? 'bg-red-500' : 'bg-blue-500'
              } shadow-[0_0_0_4px_rgba(59,130,246,0.1)] z-10`}></div>

              <div 
                className={`bg-gray-800 rounded-lg p-5 border shadow-md transition-all cursor-pointer group ${isExpanded ? 'border-blue-500/50 ring-1 ring-blue-500/20' : 'border-gray-700 hover:border-gray-600'}`}
                onClick={() => toggleExpand(index)}
