                                <div className="space-y-2">
                                    <div className="flex items-center gap-2 text-gray-300">
                                        <MapPin className="w-4 h-4 text-gray-500" />
                                        <span>Coordinates: {stop.coordinates ? `${stop.coordinates.lat.toFixed(4)}, ${stop.coordinates.lng.toFixed(4)}` : 'N/A'}</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-gray-300">
                                        <Calendar className="w-4 h-4 text-gray-500" />
                                        <span>Exact Date: {exactDate || 'Set start date to see'}</span>
