const itinerarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    routeName: { type: Type.STRING, description: "A catchy name for this route" },
    totalDistance: { type: Type.STRING, description: "Estimated total distance" },
    totalDuration: { type: Type.STRING, description: "Estimated total travel duration including stay nights" },
    summary: { type: Type.STRING, description: "A brief summary of why this route is profitable/good" },
    stops: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day: { type: Type.INTEGER },
          city: { type: Type.STRING },
          description: { type: Type.STRING, description: "Why this stop is profitable or strategic" },
          demandScore: { type: Type.INTEGER, description: "Market demand score 0-100 based on the provided keywords" },
          nightsToStay: { type: Type.INTEGER, description: "Recommended nights to stay based on strict scoring logic" },
          travelToNext: { type: Type.STRING, description: "Time to next stop or destination" },
          transportMode: { type: Type.STRING, description: "The specific mode of transport to reach the NEXT stop (Car, Bus, Plane)" },
          activity: { type: Type.STRING, description: "Recommended professional/business activity matching the keywords" },
          coordinates: {
             type: Type.OBJECT,
             properties: {
                lat: { type: Type.NUMBER },
                lng: { type: Type.NUMBER }
             }
          }
        },
        required: ["day", "city", "description", "demandScore", "nightsToStay", "travelToNext", "activity"],
      },
    },
  },
  required: ["routeName", "totalDistance", "totalDuration", "stops", "summary"],
};

export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();

  const mandatoryStopsText = data.mandatoryStops
    .map(s => {
      let info = s.location;
      if (s.date) info += ` (Target Date: ${s.date})`;
      if (s.nights) info += ` (Stay: ${s.nights} nights)`;
      return info;
    })
    .join(', ');

  const destinationText = data.destinationDate 
    ? `${data.destination} (Target Arrival: ${data.destinationDate})` 
    : data.destination;

  const prompt = `
    Act as an expert travel logistician for a professional Male Massage Therapist targeting the LGBTQ+ market.
    Plan a road trip from ${data.origin} to ${destinationText}.

    Parameters:
    - Mode: ${data.travelMode}
    - Max Driving Per Day: ${data.maxDriveHours} hours (CRITICAL: ensure travel time between overnight stops does NOT exceed this significantly).
    - Mandatory stops: ${mandatoryStopsText} (Must be included and logically sequenced).
    - Dates: ${data.startDate || 'Not specified'} to ${data.endDate || 'Not specified'}.

    ${KEYWORD_MARKET_DATA}

    STRICT STOP CLASSIFICATION RULES (DEFINITIVE):
    You MUST calculate a 'Demand Score' (0-100) for each city based on the provided keywords and search volume.
    Then, determine 'nightsToStay' using these EXACT thresholds:

    1. Score < 40: ❌ SKIP. (Do not stop, unless it is a Mandatory Stop provided by user).
    2. Score 40-59: ✅ 1 Night. (Low demand, only stop if it's directly on the route).
    3. Score 60-84: ✅ 2 Nights. (Mid demand).
    4. Score >= 85: ✅ 3 Nights. (High demand / Spike zone).

    SAFETY RULE (CRITICAL):
    Even if Score >= 40, DO NOT STOP if:
    - Monthly search volume for main keywords is < 500.
    - City is significantly off the logical route.
    - No specific keywords from the list are active in that area.
    (Exception: Mandatory stops provided by user must ALWAYS be included with their requested nights).

    Output Logic:
    - If a city qualifies for a stop, use the calculated nightsToStay.
    - For Mandatory Stops, use the user's requested 'nights' count if provided, otherwise fallback to the score-based logic but ensure at least 1 night.

    Goal:
    - Transform travel into opportunity.
    - Logically sequence the route.
    - Provide approximate lat/lng coordinates for each city.

    ${isAlternative ? 'Provide a DIFFERENT route than the most obvious one, exploring alternative cities.' : 'Provide the most optimal and profitable route.'}

    Output JSON with the following structure:
    - routeName, totalDistance, totalDuration, summary
    - stops: Array of objects with day (cumulative), city, description, demandScore, nightsToStay, travelToNext, transportMode, activity, coordinates {lat, lng}.
  `;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const result = JSON.parse(text) as Itinerary;

    // Attach the start date and mode from input to the result so the display component can use it
    if (data.startDate) {
        result.startDate = data.startDate;
    }
    result.travelMode = data.travelMode;

    return result;
  } catch (error) {
    console.error("Error generating itinerary:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { Itinerary, Stop, TravelMode } from '../types';
import { Map, Clock, TrendingUp, Navigation, Star, Moon, Calendar, MapPin, ChevronDown, ChevronUp, Car, Bus, Plane, Shuffle, ArrowRight } from 'lucide-react';
import { DemandChart } from './DemandChart';

interface ItineraryDisplayProps {
  itinerary: Itinerary | null;
}

export const ItineraryDisplay: React.FC<ItineraryDisplayProps> = ({ itinerary }) => {
  const [expandedStopIndex, setExpandedStopIndex] = useState<number | null>(null);

  if (!itinerary) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-8 bg-gray-50/50 rounded-2xl border-2 border-dashed border-gray-200 lg:mr-6 lg:mt-6">
        <div className="bg-white p-6 rounded-full shadow-lg mb-6">
           <Map className="w-12 h-12 text-[#FF385C]" />
        </div>
        <h3 className="text-2xl font-bold text-gray-800 mb-3">Ready to Plan?</h3>
        <p className="max-w-md text-gray-500 leading-relaxed">
          Configure your trip on the left and tap <span className="font-bold text-gray-900">"Explore Plan"</span>. We'll find the most profitable stops for your journey.
        </p>
      </div>
    );
  }

  const toggleExpand = (index: number) => {
    setExpandedStopIndex(expandedStopIndex === index ? null : index);
  };

  const getExactDate = (dayOffset: number): string | null => {
    if (!itinerary.startDate) return null;
    const date = new Date(itinerary.startDate);
    // Add days. Note: Stop Day 1 = Start Date.
    date.setDate(date.getDate() + (dayOffset - 1)); 
    // Format: "Mon, Jan 15"
    return date.toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric' });
  };

  const getModeIcon = (mode: string | undefined) => {
    const normalizeMode = mode?.toLowerCase() || '';
    if (normalizeMode.includes('car')) return <Car className="w-5 h-5" />;
    if (normalizeMode.includes('bus')) return <Bus className="w-5 h-5" />;
    if (normalizeMode.includes('plane') || normalizeMode.includes('flight')) return <Plane className="w-5 h-5" />;
    if (normalizeMode.includes('mixed')) return <Shuffle className="w-5 h-5" />;
    return <Navigation className="w-5 h-5" />;
  };

  return (
    <div className="h-full overflow-y-auto px-4 pb-12 lg:pr-6 custom-scrollbar">
      {/* Hero Header */}
      <div className="bg-white rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.06)] border border-gray-100 overflow-hidden mb-8 mt-2 lg:mt-6">
        <div className="bg-gradient-to-r from-[#FF385C] to-[#E00B41] h-32 relative">
             <div className="absolute -bottom-10 right-8 bg-white p-4 rounded-2xl shadow-lg border border-gray-100">
                <div className="text-center">
                    <p className="text-[10px] uppercase font-bold text-gray-400">Total Profitability</p>
                    <div className="flex items-center gap-1 justify-center">
                        <Star className="w-5 h-5 text-yellow-400 fill-yellow-400" />
                        <span className="text-2xl font-black text-gray-900">High</span>
                    </div>
                </div>
             </div>
        </div>
        <div className="px-8 pt-6 pb-8">
            <h2 className="text-3xl font-extrabold text-gray-900 mb-2">{itinerary.routeName}</h2>
            <p className="text-gray-500 text-lg leading-relaxed mb-6 max-w-2xl">{itinerary.summary}</p>

            <div className="flex flex-wrap gap-3">
                <div className="px-4 py-2 bg-gray-50 rounded-full border border-gray-200 flex items-center gap-2 text-sm font-semibold text-gray-700">
                    <Navigation className="w-4 h-4 text-[#FF385C]" />
                    {itinerary.totalDistance}
                </div>
                 <div className="px-4 py-2 bg-gray-50 rounded-full border border-gray-200 flex items-center gap-2 text-sm font-semibold text-gray-700">
                    <Clock className="w-4 h-4 text-[#FF385C]" />
                    {itinerary.totalDuration}
                </div>
                 <div className="px-4 py-2 bg-gray-50 rounded-full border border-gray-200 flex items-center gap-2 text-sm font-semibold text-gray-700">
                    {getModeIcon(itinerary.travelMode)}
                    {itinerary.travelMode || 'Car'}
                </div>
            </div>
        </div>
      </div>

      {/* Demand Chart */}
      <div className="mb-8">
         <DemandChart stops={itinerary.stops} />
      </div>

      {/* Timeline */}
      <div className="relative pl-4 lg:pl-8 space-y-0">
        <div className="absolute left-[31px] lg:left-[47px] top-4 bottom-10 w-0.5 bg-gray-200"></div>

        {itinerary.stops.map((stop, index) => {
          const isExpanded = expandedStopIndex === index;
          const exactDate = getExactDate(stop.day);
          const legIcon = getModeIcon(stop.transportMode || itinerary.travelMode);
          const isLast = index === itinerary.stops.length - 1;

          return (
            <div key={index} className="relative pb-10 last:pb-0">
              {/* Timeline Marker */}
              <div className={`absolute left-[19px] lg:left-[35px] top-6 w-6 h-6 rounded-full border-[3px] z-10 bg-white ${
                index === 0 ? 'border-green-500' : isLast ? 'border-black' : 'border-[#FF385C]'
              } shadow-sm flex items-center justify-center`}>
                  {index === 0 && <div className="w-2 h-2 bg-green-500 rounded-full"></div>}
                  {isLast && <div className="w-2 h-2 bg-black rounded-full"></div>}
              </div>

              <div 
                className={`ml-12 lg:ml-16 bg-white rounded-2xl p-6 border transition-all cursor-pointer group hover:shadow-lg ${isExpanded ? 'border-[#FF385C] shadow-md' : 'border-gray-200 shadow-sm'}`}
                onClick={() => toggleExpand(index)}
              >
                <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-2 flex-wrap">
                      <span className="bg-gray-100 text-gray-600 text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wide">
                        Day {stop.day}
                      </span>
                      {exactDate && (
                         <div className="flex items-center gap-1.5 text-gray-500 text-xs font-semibold">
                            <Calendar className="w-3 h-3" />
                            {exactDate}
                         </div>
                      )}
                      <div className="flex items-center gap-1.5 bg-indigo-50 text-indigo-600 px-2 py-1 rounded-full text-xs font-bold">
                        <Moon className="w-3 h-3" />
                        {stop.nightsToStay} Nights
                      </div>
                    </div>

                    <h3 className="text-xl font-extrabold text-gray-900 flex items-center gap-2 group-hover:text-[#FF385C] transition-colors">
                        {stop.city}
                        {isExpanded ? <ChevronUp className="w-4 h-4 text-gray-400" /> : <ChevronDown className="w-4 h-4 text-gray-400" />}
                    </h3>

                    <div className="flex items-center gap-2 text-sm text-gray-500 mt-1 font-medium">
                       <TrendingUp className="w-4 h-4 text-green-500" />
                       Opportunity: {stop.activity}
                    </div>
                  </div>

                  <div className="flex flex-col items-end">
