export enum TravelMode {
  Car = 'Car',
  Bus = 'Bus',
  Plane = 'Plane',
  Mixed = 'Mixed'
}

export interface Stop {
  city: string;
  day: number;
  description: string;
  demandScore: number; // 0-100
  travelToNext: string;
  transportMode?: string;
  activity: string;
  nightsToStay: number;
  targetArrivalDate?: string; // Reflected from mandatory stop input
  coordinates?: {
    lat: number;
    lng: number;
  };
}

export interface Itinerary {
  routeName: string;
  totalDistance: string;
  totalDuration: string;
  stops: Stop[];
  summary: string;
  startDate?: string;
  travelMode?: TravelMode;
}

export interface MandatoryStop {
  location: string;
  date: string; // Keep for legacy or general use
  arrivalDate?: string; // Explicit arrival date request
  nights: number;
}

export interface TripFormData {
  origin: string;
  destination: string;
  destinationDate: string;
  startDate: string;
  endDate: string;
  mandatoryStops: MandatoryStop[];
  numberOfStops: number; // Treated as a target/preference
  maxDriveHours: number;
  travelMode: TravelMode;
  travelModeDetail?: string; // For Mixed mode specifics
}

