            <MapPin className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
          </div>
          <div className="relative p-4 hover:bg-gray-50 transition-colors">
            <label className="text-[10px] font-bold uppercase tracking-wider text-gray-500 block mb-1">Destination</label>
            <input
              type="text"
              value={formData.destination}
              onChange={(e) => handleChange('destination', e.target.value)}
              className="w-full bg-transparent text-gray-900 font-semibold text-lg placeholder-gray-400 focus:outline-none"
              placeholder="Where are you going?"
            />
            <MapPin className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
          </div>
           {/* Destination Date */}
           <div className="relative p-4 border-t border-gray-100 hover:bg-gray-50 transition-colors bg-gray-50/50">
            <label className="text-[10px] font-bold uppercase tracking-wider text-gray-500 block mb-1">Target Arrival Date (Optional)</label>
            <input
              type="date"
              value={formData.destinationDate}
