                              value={stop.arrivalDate || stop.date || ''}
                              onChange={(e) => handleStopChange(index, 'arrivalDate', e.target.value)}
                              className="w-full bg-transparent text-xs text-gray-600 focus:outline-none"
                            />
                    </div>
