                {formData.travelMode === TravelMode.Mixed && (
                  <div className="bg-gray-50 p-3 rounded-lg border border-gray-200">
                      <div className="flex items-center gap-2 mb-1">
                        <Info className="w-3 h-3 text-gray-500" />
