export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();

  const mandatoryStopsText = data.mandatoryStops
    .map(s => {
      let info = s.location;
      const dateVal = s.arrivalDate || s.date;
      if (dateVal) info += ` (Must arrive on: ${dateVal})`;
      if (s.nights) info += ` (Stay: ${s.nights} nights)`;
      return info;
    })
    .join(', ');

  const destinationText = data.destinationDate 
    ? `${data.destination} (Target Arrival: ${data.destinationDate})` 
    : data.destination;

  let modeText: string = data.travelMode;
  if (data.travelMode === TravelMode.Mixed && data.travelModeDetail) {
    modeText = `${TravelMode.Mixed}: ${data.travelModeDetail}`;
  }

  const prompt = `
    Act as a high-precision algorithmic engine for a professional Male Massage Therapist.
    Plan a profitable road trip from ${data.origin} to ${destinationText}.

    Context:
    - Mode: ${modeText}
    - Max Drive: ${data.maxDriveHours}h/day.
    - Dates: ${data.startDate || 'TBD'} to ${data.endDate || 'TBD'}.
    - Mandatory Stops: ${mandatoryStopsText}.

    ${KEYWORD_MARKET_DATA}

    YOU MUST EXECUTE THE FOLLOWING ALGORITHM STRICTLY:

    =========================================
    PHASE 1: AREA DEMAND CLUSTER (ADC)
    =========================================
    Do not just evaluate single cities. You must identify "Clusters".

    1. **Grouping Logic**:
       - Radius: ~60 minutes travel time (not just distance).
       - If cities are within this radius, group them.

    2. **Anchor City**:
       - Select the city with the highest Volume (Ads) or best infrastructure as the Anchor. This is the 'city' name in the output.

    3. **Cluster Volume Aggregation**:
       - Simulate the sum: ClusterVolume = SUM(Volume_City_i * weight_distance_i)
       - Weight: exp(-minutes_away / 45).
       - *This allows small towns to qualify if they are part of a dense cluster.*

    4. **Cluster Trend**:
       - ClusterTrend = Median(Trends) + Max(Trend_Velocity).
       - This prevents statistical noise.

    =========================================
    PHASE 2: OPPORTUNITY SCORE FORMULA (0-100)
    =========================================
    For each candidate Cluster (or isolated City), calculate the score using these normalized variables:

    - Vn (Volume): Normalized Log Volume.
    - Tn (Trend): Current interest level (0-1).
    - Dn (Velocity): Growth speed (+10% in last 4-8 weeks = 1.0).
    - Sn (Seasonality): Historical pattern match.
    - En (Events): External events window.
    - Gn (Geo): 1.0 minus route deviation penalty.
    - Pn (SERP): Competition density.

    **SCORE EQUATION:**
    Score = 100 * (0.30*Vn + 0.25*Tn + 0.15*Dn + 0.10*Sn + 0.10*En + 0.05*Pn + 0.05*Gn)

    =========================================
    PHASE 3: THE HARD GATE (CRITICAL)
    =========================================
    Discard any Cluster/City that does not meet ALL these criteria (unless it is a User Mandatory Stop):

    1. **Volume**: Cluster Volume >= 1,500 (absolute monthly searches).
    2. **Trend**: Cluster Trend Index >= 20.
    3. **Velocity**: At least 2 cities in cluster have positive trend velocity.
    4. **Geo**: Deviation from route <= 15% (Time or Distance).
    5. **Final Score**: >= 40.

    IF FAIL -> SKIP.
    IF PASS -> PROCEED TO CONVERSION.

    =========================================
    PHASE 4: CONVERSION TO NIGHTS (PROBABILITY)
    =========================================
    Convert the Score into a "Calibrated Probability" of a profitable spike.

    - Score < 40: SKIP.
    - Score 40-59 (Prob >= 80%): 1 Night. (Safety margin).
    - Score 60-84 (Prob >= 90%): 2 Nights.
    - Score >= 85 (Prob >= 95%): 3 Nights. (High confidence).

    =========================================
    OUTPUT INSTRUCTIONS
    =========================================
    - Apply this logic to find hidden gems (Clusters) along the route.
    - Provide traffic estimates for each leg.
    - If a specific arrival date is requested in Mandatory Stops, respect it in the timeline.
    - Generate a JSON response matching the schema.

    ${isAlternative ? 'Focus on secondary Clusters that meet the gate but are off the main interstate.' : 'Focus on the highest scoring Clusters on the direct route.'}
  `;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const result = JSON.parse(text) as Itinerary;

    // Post-processing: Force target arrival dates from user input if the AI missed them
    if (result.stops && data.mandatoryStops.length > 0) {
      result.stops = result.stops.map(stop => {
        const match = data.mandatoryStops.find(ms => 
          stop.city.toLowerCase().includes(ms.location.toLowerCase()) || 
          ms.location.toLowerCase().includes(stop.city.toLowerCase())
        );

        if (match) {
          const userDate = match.arrivalDate || match.date;
          if (userDate) {
            return { ...stop, targetArrivalDate: userDate };
          }
        }
        return stop;
      });
    }

    if (data.startDate) {
        result.startDate = data.startDate;
    }
    result.travelMode = data.travelMode;

    return result;
  } catch (error) {
    console.error("Error generating itinerary:", error);
    throw error;
  }
};

