                    <p className="text-[10px] uppercase font-bold text-gray-400">Total Profitability</p>
                    <div className="flex items-center gap-1 justify-center">
                        <Star className="w-5 h-5 text-yellow-400 fill-yellow-400" />
                        <span className="text-2xl font-black text-gray-900">High</span>
                    </div>
                </div>
             </div>
        </div>
        <div className="px-8 pt-6 pb-8">
            <h2 className="text-3xl font-extrabold text-gray-900 mb-2">{itinerary.routeName}</h2>
            <p className="text-gray-500 text-lg leading-relaxed mb-6 max-w-2xl">{itinerary.summary}</p>

            <div className="flex flex-wrap gap-3">
                <div className="px-4 py-2 bg-gray-50 rounded-full border border-gray-200 flex items-center gap-2 text-sm font-semibold text-gray-700">
                    <Navigation className="w-4 h-4 text-[#FF385C]" />
                    {itinerary.totalDistance}
                </div>
                 <div className="px-4 py-2 bg-gray-50 rounded-full border border-gray-200 flex items-center gap-2 text-sm font-semibold text-gray-700">
                    <Clock className="w-4 h-4 text-[#FF385C]" />
                    {itinerary.totalDuration}
                </div>
                 <div className="px-4 py-2 bg-gray-50 rounded-full border border-gray-200 flex items-center gap-2 text-sm font-semibold text-gray-700">
                    {getModeIcon(itinerary.travelMode)}
                    {itinerary.travelMode || 'Car'}
                </div>
            </div>
        </div>
      </div>

      {/* Demand Chart */}
      <div className="mb-8">
         <DemandChart stops={itinerary.stops} />
      </div>

      {/* Timeline */}
      <div className="relative pl-4 lg:pl-8 space-y-0">
        <div className="absolute left-[31px] lg:left-[47px] top-4 bottom-10 w-0.5 bg-gray-200"></div>

        {itinerary.stops.map((stop, index) => {
          const isExpanded = expandedStopIndex === index;
          const exactDate = getExactDate(stop.day);
          const legIcon = getModeIcon(stop.transportMode || itinerary.travelMode);
          const isLast = index === itinerary.stops.length - 1;

          return (
            <div key={index} className="relative pb-10 last:pb-0">
              {/* Timeline Marker */}
              <div className={`absolute left-[19px] lg:left-[35px] top-6 w-6 h-6 rounded-full border-[3px] z-10 bg-white ${
                index === 0 ? 'border-green-500' : isLast ? 'border-black' : 'border-[#FF385C]'
              } shadow-sm flex items-center justify-center`}>
                  {index === 0 && <div className="w-2 h-2 bg-green-500 rounded-full"></div>}
                  {isLast && <div className="w-2 h-2 bg-black rounded-full"></div>}
              </div>

              <div 
                className={`ml-12 lg:ml-16 bg-white rounded-2xl p-6 border transition-all cursor-pointer group hover:shadow-lg ${isExpanded ? 'border-[#FF385C] shadow-md' : 'border-gray-200 shadow-sm'}`}
                onClick={() => toggleExpand(index)}
              >
                <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-2 flex-wrap">
                      <span className="bg-gray-100 text-gray-600 text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wide">
                        Day {stop.day}
                      </span>
                      {exactDate && (
                         <div className="flex items-center gap-1.5 text-gray-500 text-xs font-semibold">
                            <Calendar className="w-3 h-3" />
                            {exactDate}
                         </div>
                      )}
                      <div className="flex items-center gap-1.5 bg-indigo-50 text-indigo-600 px-2 py-1 rounded-full text-xs font-bold">
                        <Moon className="w-3 h-3" />
                        {stop.nightsToStay} Nights
                      </div>

                      {/* PROMINENT Target Arrival Badge */}
                      {stop.targetArrivalDate && (
                        <div className="flex items-center gap-1.5 bg-[#FF385C] text-white px-3 py-1 rounded-full text-xs font-bold shadow-sm animate-pulse">
                          <Target className="w-3 h-3" />
                          MUST ARRIVE: {stop.targetArrivalDate}
                        </div>
                      )}
                    </div>

                    <h3 className="text-xl font-extrabold text-gray-900 flex items-center gap-2 group-hover:text-[#FF385C] transition-colors">
                        {stop.city}
                        {isExpanded ? <ChevronUp className="w-4 h-4 text-gray-400" /> : <ChevronDown className="w-4 h-4 text-gray-400" />}
                    </h3>

                    <div className="flex items-center gap-2 text-sm text-gray-500 mt-1 font-medium">
                       <TrendingUp className="w-4 h-4 text-green-500" />
                       Opportunity: {stop.activity}
                    </div>
                  </div>

                  <div className="flex flex-col items-end">
                     <div className={`text-2xl font-black ${
                       stop.demandScore >= 85 ? 'text-green-500' : stop.demandScore >= 60 ? 'text-blue-500' : stop.demandScore >= 40 ? 'text-yellow-500' : 'text-gray-300'
                     }`}>{stop.demandScore}</div>
                     <span className="text-[10px] font-bold text-gray-400 uppercase">Demand Score</span>
                  </div>
                </div>

                {isExpanded && (
                    <div className="mt-6 pt-6 border-t border-gray-100 animate-in fade-in slide-in-from-top-2 duration-300">
                         <p className="text-gray-600 leading-relaxed mb-6">
                            {stop.description}
                        </p>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 bg-gray-50 p-4 rounded-xl">
                            <div>
                                <h4 className="text-gray-400 text-[10px] font-bold uppercase mb-3">Location</h4>
                                <div className="space-y-2">
                                    <div className="flex items-center gap-2 text-gray-700 text-sm font-medium">
                                        <MapPin className="w-4 h-4 text-gray-400" />
                                        <span>{stop.coordinates ? `${stop.coordinates.lat.toFixed(4)}, ${stop.coordinates.lng.toFixed(4)}` : 'N/A'}</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-gray-700 text-sm font-medium">
                                        <Calendar className="w-4 h-4 text-gray-400" />
                                        <span>Check-in: {exactDate || 'TBD'}</span>
                                    </div>
                                    {stop.targetArrivalDate && (
                                       <div className="flex items-center gap-2 text-[#FF385C] text-sm font-bold bg-red-50 p-2 rounded border border-red-100">
                                          <Target className="w-4 h-4" />
                                          <span>Mandatory Arrival: {stop.targetArrivalDate}</span>
                                      </div>
                                    )}
                                </div>
                            </div>
                             <div>
                                <h4 className="text-gray-400 text-[10px] font-bold uppercase mb-3">Logistics</h4>
                                <div className="space-y-2">
                                     <div className="flex items-center gap-2 text-gray-700 text-sm font-medium">
                                        <Moon className="w-4 h-4 text-gray-400" />
                                        <span>{stop.nightsToStay} Night{stop.nightsToStay !== 1 ? 's' : ''} stay</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-gray-700 text-sm font-medium">
                                        <span className="text-gray-400">{legIcon}</span>
                                        <span>Arriving by {stop.transportMode || itinerary.travelMode || 'Mixed'}</span>
                                    </div>
                                    {stop.trafficCondition && (
                                       <div className="flex items-center gap-2 text-orange-600 text-sm font-medium bg-orange-50 px-2 py-1 rounded">
                                          <Car className="w-4 h-4" />
                                          <span className="line-clamp-1">{stop.trafficCondition}</span>
                                       </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                )}
              </div>

               {/* PROMINENT TRAVEL TIME CARD & MAPS LINK */}
                {!isLast && (
                  <div className="ml-12 lg:ml-16 mt-4">
                      <div className="flex flex-col sm:flex-row gap-3">
                        <div className="flex-1 flex items-center p-4 rounded-xl bg-white border border-gray-200 shadow-sm hover:shadow-md transition-shadow group/card relative overflow-hidden">
                          <div className="absolute left-0 top-0 bottom-0 w-1 bg-gray-900 group-hover/card:bg-[#FF385C] transition-colors"></div>
                          <div className="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center mr-4 text-gray-700 group-hover/card:text-[#FF385C] transition-colors">
                                {legIcon}
                          </div>
                          <div className="flex-1">
                              <div className="flex justify-between items-center">
                                  <div>
                                      <p className="text-[10px] uppercase tracking-wider text-gray-400 font-bold mb-0.5">Travel to next stop</p>
                                      <p className="text-lg font-bold text-gray-900">{stop.travelToNext}</p>
                                  </div>
                                  <ArrowRight className="w-5 h-5 text-gray-300 group-hover/card:text-gray-900 transition-colors" />
                              </div>
                          </div>
                        </div>

                        {/* MAP LINK BUTTON */}
                        <a 
                          href={getMapsTrafficLink(stop.city, itinerary.stops[index + 1].city)}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="sm:w-auto w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl bg-blue-50 border border-blue-100 text-blue-600 hover:bg-blue-100 hover:border-blue-200 transition-all group/map"
                        >
                            <Map className="w-5 h-5" />
                            <span className="font-bold text-sm">Live Traffic Map</span>
                            <ExternalLink className="w-3 h-3 opacity-50 group-hover/map:opacity-100" />
                        </a>
                      </div>
                  </div>
                )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Plus, X, MapPin, Calendar, Clock, Car, Bus, Plane, Shuffle, Search, Minus, Info, Edit2, Check, ChevronDown, ChevronUp } from 'lucide-react';
import { TripFormData, TravelMode, MandatoryStop } from '../types';
import { DEFAULT_FORM_DATA } from '../constants';

interface InputFormProps {
  initialData: TripFormData;
  onSubmit: (data: TripFormData, isAlternative: boolean) => void;
  isLoading: boolean;
}

const STORAGE_KEY = 'roadTripPro_formData';

export const InputForm: React.FC<InputFormProps> = ({ initialData, onSubmit, isLoading }) => {
  // Initialize state from localStorage or fall back to initialData
  const [formData, setFormData] = useState<TripFormData>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : initialData;
    } catch (e) {
      console.warn('Failed to load form data from local storage', e);
      return initialData;
    }
  });

  const [editingStopIndex, setEditingStopIndex] = useState<number | null>(null);

  // Persist to localStorage whenever formData changes
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(formData));
    } catch (e) {
      console.warn('Failed to save form data to local storage', e);
    }
  }, [formData]);

  const handleChange = (field: keyof TripFormData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleStopChange = (index: number, field: keyof MandatoryStop, value: string | number) => {
    const newStops = [...formData.mandatoryStops];
    // Cast appropriately if updating numeric fields
    const updatedValue = field === 'nights' ? Number(value) : value;
    newStops[index] = { ...newStops[index], [field]: updatedValue };
    handleChange('mandatoryStops', newStops);
  };

  const addStop = () => {
    const newIndex = formData.mandatoryStops.length;
    handleChange('mandatoryStops', [...formData.mandatoryStops, { location: '', date: '', arrivalDate: '', nights: 1 }]);
    setEditingStopIndex(newIndex); // Auto-open edit mode for new stop
  };

  const removeStop = (index: number) => {
    const newStops = formData.mandatoryStops.filter((_, i) => i !== index);
    handleChange('mandatoryStops', newStops);
    if (editingStopIndex === index) setEditingStopIndex(null);
  };

  const toggleEditStop = (index: number) => {
    if (editingStopIndex === index) {
      setEditingStopIndex(null); // Save/Close
    } else {
      setEditingStopIndex(index); // Open
    }
  };

  const getModeIcon = (mode: string) => {
    switch (mode) {
      case TravelMode.Car: return <Car className="w-5 h-5" />;
      case TravelMode.Bus: return <Bus className="w-5 h-5" />;
      case TravelMode.Plane: return <Plane className="w-5 h-5" />;
      default: return <Shuffle className="w-5 h-5" />;
    }
  };

  return (
    <div className="h-full flex flex-col bg-white">
      <div className="p-6 pb-2 border-b border-gray-100 lg:border-none">
        <h2 className="text-2xl font-bold text-gray-800">Where to?</h2>
        <p className="text-gray-500 text-sm mt-1">Configure your professional road trip</p>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
        {/* Origin & Destination Card */}
        <div className="bg-white border border-gray-200 rounded-2xl shadow-[0_6px_16px_rgba(0,0,0,0.08)] overflow-hidden">
          <div className="relative p-4 border-b border-gray-100 hover:bg-gray-50 transition-colors">
            <label className="text-[10px] font-bold uppercase tracking-wider text-gray-500 block mb-1">Origin</label>
            <input
              type="text"
              value={formData.origin}
              onChange={(e) => handleChange('origin', e.target.value)}
              className="w-full bg-transparent text-gray-900 font-semibold text-lg placeholder-gray-400 focus:outline-none"
              placeholder="Where are you starting?"
            />
            <MapPin className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
          </div>
          <div className="relative p-4 hover:bg-gray-50 transition-colors">
            <label className="text-[10px] font-bold uppercase tracking-wider text-gray-500 block mb-1">Destination</label>
            <input
              type="text"
              value={formData.destination}
              onChange={(e) => handleChange('destination', e.target.value)}
              className="w-full bg-transparent text-gray-900 font-semibold text-lg placeholder-gray-400 focus:outline-none"
              placeholder="Where are you going?"
            />
            <MapPin className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
          </div>
           {/* Destination Date */}
           <div className="relative p-4 border-t border-gray-100 hover:bg-gray-50 transition-colors bg-gray-50/50">
            <label className="text-[10px] font-bold uppercase tracking-wider text-gray-500 block mb-1">Target Arrival Date (Optional)</label>
            <input
              type="date"
              value={formData.destinationDate}
              onChange={(e) => handleChange('destinationDate', e.target.value)}
              className="w-full bg-transparent text-gray-700 font-medium focus:outline-none text-sm"
            />
          </div>
        </div>

        {/* Dates Card */}
        <div className="bg-white border border-gray-200 rounded-2xl shadow-[0_6px_16px_rgba(0,0,0,0.08)] overflow-hidden flex flex-col sm:flex-row">
           <div className="flex-1 p-4 border-b sm:border-b-0 sm:border-r border-gray-100 hover:bg-gray-50 transition-colors">
            <label className="text-[10px] font-bold uppercase tracking-wider text-gray-500 block mb-1">Start Date</label>
            <input
              type="date"
              value={formData.startDate}
              onChange={(e) => handleChange('startDate', e.target.value)}
              className="w-full bg-transparent text-gray-700 font-medium focus:outline-none text-sm"
            />
          </div>
          <div className="flex-1 p-4 hover:bg-gray-50 transition-colors">
            <label className="text-[10px] font-bold uppercase tracking-wider text-gray-500 block mb-1">Return Date</label>
            <input
              type="date"
              value={formData.endDate}
              onChange={(e) => handleChange('endDate', e.target.value)}
              className="w-full bg-transparent text-gray-700 font-medium focus:outline-none text-sm"
            />
          </div>
        </div>

        {/* Mandatory Stops */}
        <div>
          <div className="flex items-center justify-between mb-3">
             <label className="text-sm font-bold text-gray-800">Must-visit Cities</label>
             <button
              onClick={addStop}
              className="text-xs font-bold text-gray-900 underline hover:text-[#FF385C] transition-colors flex items-center gap-1"
            >
              <Plus className="w-3 h-3" /> Add City
            </button>
          </div>

          <div className="space-y-3">
            {formData.mandatoryStops.map((stop, index) => {
              const isEditing = editingStopIndex === index;
              return (
                <div key={index} className={`rounded-xl border transition-all duration-200 ${isEditing ? 'bg-white border-[#FF385C] shadow-md' : 'bg-gray-50 border-gray-200 hover:border-gray-300'}`}>
                  {isEditing ? (
                    // Edit Mode
                    <div className="p-4 space-y-3">
                      <div className="flex justify-between items-center mb-2">
                        <span className="text-xs font-bold text-[#FF385C] uppercase tracking-wider">Editing Stop #{index + 1}</span>
                        <button onClick={() => toggleEditStop(index)} className="text-gray-400 hover:text-green-600">
                          <Check className="w-5 h-5" />
                        </button>
                      </div>

                      <div>
                        <label className="text-[10px] font-bold text-gray-400 uppercase block mb-1">City Location</label>
                        <input
                          type="text"
                          value={stop.location}
                          onChange={(e) => handleStopChange(index, 'location', e.target.value)}
                          className="w-full bg-gray-50 border border-gray-200 rounded px-3 py-2 text-sm font-semibold text-gray-900 focus:outline-none focus:border-[#FF385C]"
                          placeholder="e.g. Chicago, IL"
                          autoFocus
                        />
                      </div>

                      <div className="flex gap-3">
                         <div className="flex-1">
                            <label className="text-[10px] font-bold text-gray-400 uppercase block mb-1">Required Arrival</label>
                             <div className="flex items-center gap-2 bg-gray-50 rounded border border-gray-200 px-2 py-1.5">
                                 <Calendar className="w-4 h-4 text-gray-400" />
                                 <input
                                      type="date"
                                      value={stop.arrivalDate || stop.date || ''}
                                      onChange={(e) => handleStopChange(index, 'arrivalDate', e.target.value)}
                                      className="w-full bg-transparent text-xs text-gray-700 focus:outline-none font-medium"
                                    />
                            </div>
                         </div>
                          <div className="w-24">
                            <label className="text-[10px] font-bold text-gray-400 uppercase block mb-1">Nights</label>
                             <div className="w-full bg-gray-50 rounded border border-gray-200 px-2 py-1.5 flex items-center gap-2">
                                <span className="text-xs text-gray-500 font-bold">Stay</span>
                                <input
                                      type="number"
                                      min={1}
                                      max={14}
                                      value={stop.nights}
                                      onChange={(e) => handleStopChange(index, 'nights', parseInt(e.target.value) || 1)}
                                      className="flex-1 bg-transparent text-sm font-bold text-gray-900 focus:outline-none text-right"
                                />
                             </div>
                          </div>
                      </div>
                    </div>
                  ) : (
                    // View Mode (Summary)
                    <div className="p-3 flex items-center justify-between group">
                       <div className="flex-1 flex flex-col cursor-pointer" onClick={() => toggleEditStop(index)}>
                          <span className="text-sm font-bold text-gray-900">{stop.location || 'New Stop'}</span>
                          <div className="flex items-center gap-2 mt-0.5">
                             <span className="text-xs text-gray-500 flex items-center gap-1">
                               <Calendar className="w-3 h-3" />
                               {stop.arrivalDate || stop.date || 'Flexible Date'}
                             </span>
                             <span className="text-gray-300">•</span>
                             <span className="text-xs text-gray-500">{stop.nights} Night{stop.nights !== 1 ? 's' : ''}</span>
                          </div>
                       </div>

                       <div className="flex items-center gap-1">
                          <button
                            onClick={() => toggleEditStop(index)}
                            className="p-2 text-gray-400 hover:text-gray-800 hover:bg-gray-200 rounded-full transition-colors"
                          >
                            <Edit2 className="w-4 h-4" />
                          </button>
                          <button
                            onClick={() => removeStop(index)}
                            className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors"
                          >
                            <X className="w-4 h-4" />
                          </button>
                       </div>
                    </div>
                  )}
                </div>
              );
            })}
             {formData.mandatoryStops.length === 0 && (
                <div className="text-center py-6 border-2 border-dashed border-gray-200 rounded-xl">
                    <p className="text-gray-400 text-sm">No mandatory stops added.</p>
                </div>
             )}
          </div>
        </div>

        {/* Preferences */}
        <div>
           <label className="text-sm font-bold text-gray-800 mb-3 block">Travel Preferences</label>
           <div className="bg-white border border-gray-200 rounded-2xl p-4 shadow-sm space-y-5">

              {/* Travel Mode */}
              <div>
                <span className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2 block">Mode of Transport</span>
                <div className="grid grid-cols-4 gap-2 mb-3">
                  {Object.values(TravelMode).map((mode) => (
                    <button
                      key={mode}
                      onClick={() => handleChange('travelMode', mode)}
                      className={`flex flex-col items-center justify-center p-2 rounded-xl border transition-all ${
                        formData.travelMode === mode
                          ? 'bg-gray-900 border-gray-900 text-white'
                          : 'bg-white border-gray-200 text-gray-600 hover:border-gray-300'
                      }`}
                    >
                      {getModeIcon(mode)}
                      <span className="text-[10px] font-bold mt-1">{mode}</span>
                    </button>
                  ))}
                </div>
                {formData.travelMode === TravelMode.Mixed && (
                  <div className="bg-gray-50 p-3 rounded-lg border border-gray-200">
                      <div className="flex items-center gap-2 mb-1">
                        <Info className="w-3 h-3 text-gray-500" />
                        <span className="text-[10px] font-bold uppercase text-gray-500">Mixed Mode Details</span>
                      </div>
                      <input 
                        type="text"
                        value={formData.travelModeDetail || ''}
                        onChange={(e) => handleChange('travelModeDetail', e.target.value)}
                        placeholder="e.g. Fly to Denver, then rent car"
                        className="w-full bg-white border border-gray-200 rounded px-2 py-1.5 text-xs text-gray-800 focus:outline-none focus:border-gray-400"
                      />
                  </div>
                )}
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <div>
                      <span className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2 block flex items-center gap-1">
                        Max Drive Hours <Clock className="w-3 h-3" />
                      </span>
                      <div className="flex items-center gap-3">
                          <input
                            type="number"
                            min={1}
                            max={24}
                            value={formData.maxDriveHours}
                            onChange={(e) => handleChange('maxDriveHours', Math.max(1, Math.min(24, parseInt(e.target.value) || 1)))}
                            className="w-full bg-gray-50 border border-gray-200 rounded-lg py-2 px-3 text-lg font-bold text-gray-900 focus:outline-none focus:ring-1 focus:ring-gray-300"
                          />
                      </div>
                  </div>
                   <div>
                      <span className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2 block">Target Stops</span>
                       <div className="relative">
                            <input
                            type="number"
                            min={1}
                            max={20}
                            value={formData.numberOfStops}
                            onChange={(e) => handleChange('numberOfStops', parseInt(e.target.value))}
                            className="w-full bg-gray-50 border border-gray-200 rounded-lg py-2 px-3 text-lg font-bold text-gray-900 focus:outline-none focus:ring-1 focus:ring-gray-300"
                            placeholder="Auto"
                          />
                       </div>
                  </div>
              </div>

           </div>
        </div>

      </div>

      <div className="p-6 border-t border-gray-100 bg-white">
        <button
          onClick={() => onSubmit(formData, false)}
          disabled={isLoading}
          className={`w-full py-4 rounded-xl font-bold text-white text-lg shadow-[0_6px_20px_rgba(255,56,92,0.4)] transition-all transform hover:scale-[1.01] active:scale-[0.98] flex items-center justify-center gap-2 ${
            isLoading 
              ? 'bg-gray-300 cursor-not-allowed shadow-none' 
              : 'bg-gradient-to-r from-[#FF385C] to-[#BD1E59]'
          }`}
        >
          {isLoading ? (
             'Generating...' 
          ) : (
            <>
                <Search className="w-5 h-5" />
                Explore Plan
            </>
          )}
        </button>

        <button
          onClick={() => onSubmit(formData, true)}
          disabled={isLoading}
          className="w-full mt-3 py-3 rounded-xl font-bold text-gray-600 bg-transparent border border-gray-200 hover:bg-gray-50 transition-all text-sm"
        >
           Generate Alternative Route
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { InputForm } from './components/InputForm';
import { ItineraryDisplay } from './components/ItineraryDisplay';
import { TripFormData, Itinerary } from './types';
import { DEFAULT_FORM_DATA } from './constants';
import { generateItinerary } from './services/geminiService';
import { MapPin, AlertTriangle, X, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [itinerary, setItinerary] = useState<Itinerary | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showResultsMobile, setShowResultsMobile] = useState(false);

  const handleGenerate = async (data: TripFormData, isAlternative: boolean) => {
    setIsLoading(true);
    setError(null);

    // Client-side Validation
    if (!data.origin || !data.origin.trim()) {
      setError("Please enter a valid Origin city.");
      setIsLoading(false);
      return;
    }
    if (!data.destination || !data.destination.trim()) {
      setError("Please enter a valid Destination city.");
      setIsLoading(false);
      return;
    }
    if (data.startDate && data.endDate) {
      const start = new Date(data.startDate);
      const end = new Date(data.endDate);
      if (start > end) {
        setError("Start Date cannot be after Return Date.");
        setIsLoading(false);
        return;
      }
    }

    if (window.innerWidth < 1024) {
      setShowResultsMobile(true);
    }
    try {
      const result = await generateItinerary(data, isAlternative);
      setItinerary(result);
    } catch (err: any) {
      setError(err.message || "Failed to generate itinerary. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-50 text-[#222222] font-sans">
      {/* Navbar - Airbnb Style */}
      <header className="flex-none bg-white border-b border-gray-200 z-50 sticky top-0 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-2 text-[#FF385C]">
            <MapPin className="w-8 h-8 fill-current" />
            <h1 className="text-2xl font-bold tracking-tight text-[#FF385C] hidden sm:block">
              RoadTripPro
            </h1>
          </div>

          <div className="hidden md:flex items-center gap-6 text-sm font-semibold text-gray-500">
            <span className="text-gray-900 border-b-2 border-gray-900 py-1">Plan a Trip</span>
            <span className="hover:text-gray-800 cursor-pointer transition-colors">Saved Routes</span>
            <span className="hover:text-gray-800 cursor-pointer transition-colors">Market Insights</span>
          </div>

          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-full bg-gray-100 border border-gray-200 flex items-center justify-center text-gray-500 hover:shadow-md transition-shadow cursor-pointer">
                <span className="text-xs font-bold">JD</span>
             </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-hidden relative">
        <div className="max-w-7xl mx-auto h-full p-0 lg:p-6 flex flex-col lg:flex-row gap-8">

          {/* Left Panel: Inputs */}
          <div className={`w-full lg:w-[400px] flex-none h-full bg-white lg:rounded-2xl lg:shadow-xl lg:border lg:border-gray-100 overflow-hidden flex flex-col z-20 transition-transform duration-300 ${showResultsMobile ? '-translate-x-full absolute' : 'translate-x-0 relative'} lg:translate-x-0 lg:relative`}>
            <InputForm 
              initialData={DEFAULT_FORM_DATA} 
              onSubmit={handleGenerate}
              isLoading={isLoading}
              error={error}
            />
            {error && (
              <div className="mx-6 mb-6 relative overflow-hidden rounded-r-xl bg-red-50 border-l-4 border-red-500 shadow-md animate-in fade-in slide-in-from-top-2">
                <div className="p-4 flex items-start gap-4">
                    <div className="flex-shrink-0 mt-0.5">
                      <AlertCircle className="w-6 h-6 text-red-600" />
                    </div>
                    <div className="flex-1">
                      <h3 className="text-sm font-bold text-red-900 mb-1">Planning Interrupted</h3>
                      <p className="text-sm text-red-700 leading-relaxed font-medium opacity-90">{error}</p>
                    </div>
                    <button 
                      onClick={() => setError(null)}
                      className="flex-shrink-0 -mr-1 -mt-1 p-2 text-red-400 hover:text-red-700 hover:bg-red-100 rounded-full transition-all"
                    >
                      <X className="w-4 h-4" />
                    </button>
                </div>
              </div>
            )}
          </div>

          {/* Right Panel: Display */}
          <div className={`flex-1 h-full overflow-hidden bg-white lg:bg-transparent rounded-none lg:rounded-2xl relative transition-transform duration-300 ${showResultsMobile ? 'translate-x-0 absolute inset-0 z-30' : 'translate-x-full absolute'} lg:translate-x-0 lg:relative lg:inset-auto lg:z-0`}>

             {/* Mobile Back Button */}
             <div className="lg:hidden absolute top-4 left-4 z-50">
                <button 
                  onClick={() => setShowResultsMobile(false)}
                  className="bg-white p-2 rounded-full shadow-lg border border-gray-100 text-gray-700 font-bold text-sm px-4"
                >
                  ← Edit Plan
                </button>
             </div>

            <ItineraryDisplay itinerary={itinerary} />

            {/* Loading Overlay */}
            {isLoading && (
              <div className="absolute inset-0 bg-white/90 backdrop-blur-sm z-40 flex flex-col items-center justify-center">
                <div className="relative w-24 h-24 mb-6">
                  <div className="absolute inset-0 border-t-4 border-[#FF385C] border-solid rounded-full animate-spin"></div>
                  <div className="absolute inset-3 border-t-4 border-rose-300 border-solid rounded-full animate-spin [animation-direction:reverse]"></div>
                </div>
                <h3 className="text-xl font-bold text-gray-800 mb-2">Planning your journey...</h3>
                <p className="text-gray-500">Analyzing Area Demand Clusters & Opportunity Scores</p>
              </div>
            )}
          </div>

        </div>
      </main>
    </div>
  );
