import React, { useState } from 'react';
import { InputForm } from './components/InputForm';
import { ItineraryDisplay } from './components/ItineraryDisplay';
import { TripFormData, Itinerary } from './types';
import { DEFAULT_FORM_DATA } from './constants';
import { generateItinerary } from './services/geminiService';
import { MapPin, X, AlertCircle, Lightbulb } from 'lucide-react';

const App: React.FC = () => {
  const [itinerary, setItinerary] = useState<Itinerary | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showResultsMobile, setShowResultsMobile] = useState(false);

  const handleGenerate = async (data: TripFormData, isAlternative: boolean) => {
    setIsLoading(true);
    setError(null);

    // Client-side Validation
    if (!data.origin || !data.origin.trim()) {
      setError("Please enter a valid Origin city.");
      setIsLoading(false);
      return;
    }
    if (!data.destination || !data.destination.trim()) {
      setError("Please enter a valid Destination city.");
      setIsLoading(false);
      return;
    }
    if (data.startDate && data.endDate) {
      const start = new Date(data.startDate);
      const end = new Date(data.endDate);
      if (start > end) {
        setError("Start Date cannot be after Return Date.");
        setIsLoading(false);
        return;
      }
    }

    if (window.innerWidth < 1024) {
      setShowResultsMobile(true);
    }
    try {
      const result = await generateItinerary(data, isAlternative);
      setItinerary(result);
    } catch (err: any) {
      setError(err.message || "Failed to generate itinerary. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const getErrorDetails = (errorMessage: string) => {
    const lowerMsg = errorMessage.toLowerCase();

    if (lowerMsg.includes('date') || lowerMsg.includes('time')) {
      return {
        title: "Date Schedule Conflict",
        suggestions: [
          "Ensure Start Date is strictly before Return Date.",
          "Check that mandatory stop arrival dates fall within the trip range.",
          "Verify the trip duration is sufficient for the number of stops."
        ]
      };
    }

    if (lowerMsg.includes('origin') || lowerMsg.includes('destination') || lowerMsg.includes('location') || lowerMsg.includes('city')) {
      return {
        title: "Location Details Missing",
        suggestions: [
          "Enter a valid 'City, State' for Origin and Destination.",
          "Check spelling of your mandatory stops.",
          "Ensure all required location fields are filled."
        ]
      };
    }

    if (lowerMsg.includes('api') || lowerMsg.includes('key') || lowerMsg.includes('quota') || lowerMsg.includes('network')) {
      return {
        title: "Connection or Service Issue",
        suggestions: [
          "Check your internet connection.",
          "The AI service might be experiencing high traffic.",
          "Verify your API key configuration."
        ]
      };
    }

    // Default catch-all
    return {
      title: "Planning Interrupted",
      suggestions: [
        "Try increasing 'Max Drive Hours' to open up more routes.",
        "Reduce constraints or mandatory stops to simplify the request.",
        "Try generating the plan again in a few moments."
      ]
    };
  };

  return (
    <div className="flex flex-col h-screen bg-gray-50 text-[#222222] font-sans">
      {/* Navbar - Airbnb Style */}
      <header className="flex-none bg-white border-b border-gray-200 z-50 sticky top-0 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-2 text-[#FF385C]">
            <MapPin className="w-8 h-8 fill-current" />
            <h1 className="text-2xl font-bold tracking-tight text-[#FF385C] hidden sm:block">
              RoadTripPro
            </h1>
          </div>

          <div className="hidden md:flex items-center gap-6 text-sm font-semibold text-gray-500">
            <span className="text-gray-900 border-b-2 border-gray-900 py-1">Plan a Trip</span>
            <span className="hover:text-gray-800 cursor-pointer transition-colors">Saved Routes</span>
            <span className="hover:text-gray-800 cursor-pointer transition-colors">Market Insights</span>
          </div>

          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-full bg-gray-100 border border-gray-200 flex items-center justify-center text-gray-500 hover:shadow-md transition-shadow cursor-pointer">
                <span className="text-xs font-bold">JD</span>
             </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-hidden relative">
        <div className="max-w-7xl mx-auto h-full p-0 lg:p-6 flex flex-col lg:flex-row gap-8">

          {/* Left Panel: Inputs */}
          <div className={`w-full lg:w-[400px] flex-none h-full bg-white lg:rounded-2xl lg:shadow-xl lg:border lg:border-gray-100 overflow-hidden flex flex-col z-20 transition-transform duration-300 ${showResultsMobile ? '-translate-x-full absolute' : 'translate-x-0 relative'} lg:translate-x-0 lg:relative`}>
            <InputForm 
              initialData={DEFAULT_FORM_DATA} 
              onSubmit={handleGenerate}
              isLoading={isLoading}
              error={error}
            />
            {error && (
              <div className="mx-6 mb-6 relative overflow-hidden rounded-xl bg-red-50 border border-red-100 shadow-sm animate-in fade-in slide-in-from-top-2">
                <div className="absolute left-0 top-0 bottom-0 w-1 bg-red-500"></div>
                <div className="p-4">
                  <div className="flex items-start gap-3">
                    <div className="flex-shrink-0 mt-0.5">
                      <AlertCircle className="w-5 h-5 text-red-600" />
                    </div>
                    <div className="flex-1">
                      <h3 className="text-sm font-bold text-red-900 mb-1">
                        {getErrorDetails(error).title}
                      </h3>
                      <p className="text-sm text-red-800 leading-relaxed font-medium mb-3">
                        {error}
                      </p>

                      <div className="bg-white/60 rounded-lg p-3 border border-red-100">
                        <div className="flex items-center gap-2 mb-2 text-red-900/70 text-xs font-bold uppercase tracking-wider">
                          <Lightbulb className="w-3 h-3" />
                          <span>Try This</span>
                        </div>
                        <ul className="space-y-1.5">
                          {getErrorDetails(error).suggestions.map((suggestion, idx) => (
                            <li key={idx} className="text-xs text-red-700 flex items-start gap-2">
                              <span className="mt-1.5 w-1 h-1 rounded-full bg-red-400 flex-shrink-0"></span>
                              <span className="leading-snug">{suggestion}</span>
                            </li>
                          ))}
                        </ul>
                      </div>
                    </div>
                    <button 
                      onClick={() => setError(null)}
                      className="flex-shrink-0 -mr-1 -mt-1 p-2 text-red-400 hover:text-red-700 hover:bg-red-100 rounded-full transition-all"
                    >
                      <X className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Right Panel: Display */}
          <div className={`flex-1 h-full overflow-hidden bg-white lg:bg-transparent rounded-none lg:rounded-2xl relative transition-transform duration-300 ${showResultsMobile ? 'translate-x-0 absolute inset-0 z-30' : 'translate-x-full absolute'} lg:translate-x-0 lg:relative lg:inset-auto lg:z-0`}>

             {/* Mobile Back Button */}
             <div className="lg:hidden absolute top-4 left-4 z-50">
                <button 
                  onClick={() => setShowResultsMobile(false)}
                  className="bg-white p-2 rounded-full shadow-lg border border-gray-100 text-gray-700 font-bold text-sm px-4"
                >
                  ← Edit Plan
                </button>
             </div>

            <ItineraryDisplay itinerary={itinerary} />

            {/* Loading Overlay */}
            {isLoading && (
              <div className="absolute inset-0 bg-white/90 backdrop-blur-sm z-40 flex flex-col items-center justify-center">
                <div className="relative w-24 h-24 mb-6">
                  <div className="absolute inset-0 border-t-4 border-[#FF385C] border-solid rounded-full animate-spin"></div>
                  <div className="absolute inset-3 border-t-4 border-rose-300 border-solid rounded-full animate-spin [animation-direction:reverse]"></div>
                </div>
                <h3 className="text-xl font-bold text-gray-800 mb-2">Planning your journey...</h3>
                <p className="text-gray-500">Analyzing Area Demand Clusters & Opportunity Scores</p>
              </div>
            )}
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

export enum TravelMode {
  Car = 'Car',
  Bus = 'Bus',
  Plane = 'Plane',
  Mixed = 'Mixed'
}

export interface Stop {
  city: string;
  day: number;
  description: string;
  demandScore: number; // 0-100
  trendVelocity: string; // New field for market momentum
  travelToNext: string;
  transportMode?: string;
  trafficCondition?: string; // Estimated typical condition or notes
  activity: string;
  nightsToStay: number;
  targetArrivalDate?: string; // Reflected from mandatory stop input
  coordinates?: {
    lat: number;
    lng: number;
  };
}

export interface Itinerary {
  routeName: string;
  totalDistance: string;
  totalDuration: string;
  stops: Stop[];
  summary: string;
  startDate?: string;
  travelMode?: TravelMode;
}

export interface MandatoryStop {
  location: string;
  date: string; // Keep for legacy or general use
  arrivalDate?: string; // Explicit arrival date request
  nights: number;
}

export interface TripFormData {
  origin: string;
  destination: string;
  destinationDate: string;
  startDate: string;
  endDate: string;
  mandatoryStops: MandatoryStop[];
  numberOfStops: number; // Treated as a target/preference
  maxDriveHours: number;
  travelMode: TravelMode;
  travelModeDetail?: string; // For Mixed mode specifics
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { TripFormData, Itinerary, TravelMode } from "../types";
import { GEMINI_MODEL } from "../constants";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

const KEYWORD_MARKET_DATA = `
MARKET DEMAND CONTEXT (Baseline Niche Data):
Use this data to determine the "Niche Relevance" of a city.
1. gay massage - High Interest
2. sensual massage - High Interest
3. male massage therapist - Moderate Interest
4. LGBTQ friendly massage - Moderate Interest
`;

const itinerarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    routeName: { type: Type.STRING, description: "A catchy name for this route" },
    totalDistance: { type: Type.STRING, description: "Estimated total distance" },
    totalDuration: { type: Type.STRING, description: "Estimated total travel duration including stay nights" },
    summary: { type: Type.STRING, description: "A brief summary of why this route is profitable/good, referencing real-world events or trends found via Search." },
    stops: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day: { type: Type.INTEGER },
          city: { type: Type.STRING },
          description: { type: Type.STRING, description: "Why this stop is profitable. Cite specific real-world factors (events, popularity) found via Search." },
          demandScore: { type: Type.INTEGER, description: "The calculated Opportunity Score (0-100)" },
          trendVelocity: { type: Type.STRING, description: "A short indicator of interest growth (e.g. '🔥 Exploding', '📈 Rising', '➡️ Stable', '📉 Cooling')." },
          nightsToStay: { type: Type.INTEGER, description: "Recommended nights based on calibrated probability" },
          travelToNext: { type: Type.STRING, description: "Time to next stop or destination" },
          transportMode: { type: Type.STRING, description: "The specific mode of transport to reach the NEXT stop (Car, Bus, Plane)" },
          targetArrivalDate: { type: Type.STRING, description: "If the user requested a specific date, reflect it here (YYYY-MM-DD)." },
          trafficCondition: { type: Type.STRING, description: "Estimated typical traffic conditions for this leg." },
          activity: { type: Type.STRING, description: "Recommended activity matching the keywords" },
          coordinates: {
             type: Type.OBJECT,
             properties: {
                lat: { type: Type.NUMBER },
                lng: { type: Type.NUMBER }
             }
          }
        },
        required: ["day", "city", "description", "demandScore", "trendVelocity", "nightsToStay", "travelToNext", "activity"],
      },
    },
  },
  required: ["routeName", "totalDistance", "totalDuration", "stops", "summary"],
};

export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();

  const mandatoryStopsText = data.mandatoryStops
    .map(s => {
      let info = s.location;
      const dateVal = s.arrivalDate || s.date;
      if (dateVal) info += ` (Must arrive on: ${dateVal})`;
      if (s.nights) info += ` (Stay: ${s.nights} nights)`;
      return info;
    })
    .join(', ');

  const destinationText = data.destinationDate 
    ? `${data.destination} (Target Arrival: ${data.destinationDate})` 
    : data.destination;

  let modeText: string = data.travelMode;
  if (data.travelMode === TravelMode.Mixed && data.travelModeDetail) {
    modeText = `${TravelMode.Mixed}: ${data.travelModeDetail}`;
  }

  const prompt = `
    Act as a high-precision algorithmic engine for a professional Male Massage Therapist.
    Plan a profitable road trip from ${data.origin} to ${destinationText}.

    Context:
    - Mode: ${modeText}
    - Max Drive: ${data.maxDriveHours}h/day.
    - Dates: ${data.startDate || 'TBD'} to ${data.endDate || 'TBD'}.
    - Mandatory Stops: ${mandatoryStopsText}.

    ${KEYWORD_MARKET_DATA}

    YOU MUST EXECUTE THE FOLLOWING 5-STEP ALGORITHM STRICTLY (The "Contract of Truth"):

    =========================================
    PASSO 1: DATA GATHERING & GROUNDING (CRITICAL)
    =========================================
    **YOU MUST USE GOOGLE SEARCH** to determine the validity and VELOCITY of potential stops.
    Do not rely solely on internal knowledge.
    1. Search for "LGBTQ events in [City] [Month/Year]" to find real demand drivers.
    2. Search for "Gay friendly cities [State]" to validate the location's reception.
    3. Search for current traffic patterns or travel advisories.
    4. **NEW**: Search for "recent trends [City] nightlife/wellness" to estimate 'Trend Velocity'. Is the scene growing, peaking, or declining?

    If a city has no active scene or negative reception found via search -> DISCARD immediately (unless User Mandatory).

    =========================================
    PASSO 2: CLUSTER DEFINITION (ADC)
    =========================================
    Don't look at cities in isolation. Build "Area Demand Clusters".
    - **Radius**: <= 60 minutes travel time.
    - **Anchor**: Select the strongest city (infrastructure/volume) as the Anchor.

    =========================================
    PASSO 3: OPPORTUNITY SCORE (0-100)
    =========================================
    Calculate the precise score based on REAL WORLD DATA found via Search.

    Score = 100 * (
      0.20 * (Search Popularity/Vibe found via Google) +
      0.20 * (Presence of Real Venues/Spas found via Google) +
      0.15 * (Upcoming Events during travel dates) +
      0.25 * (Trend Velocity - is interest surging rapidly?) +
      0.20 * (Logistical Efficiency)
    )

    =========================================
    PASSO 4: PROBABILITY CALIBRATION (CONVERSION)
    =========================================
    Convert Score to Nights based on "Calibrated Probability":

    - Score < 40: SKIP (Probability too low).
    - Score 40 - 59 (Prob >= 80%): 1 Night.
    - Score 60 - 84 (Prob >= 90%): 2 Nights.
    - Score >= 85 (Prob >= 95%): 3 Nights (High Confidence).

    =========================================
    PASSO 5: ROUTE ENGINE OUTPUT
    =========================================
    - Sequence the valid clusters/stops logically.
    - Respect specific arrival dates if provided.
    - Provide estimated traffic conditions.
    - Return JSON matching the schema, including the 'trendVelocity' field.

    ${isAlternative ? 'Focus on high-scoring Clusters that are slightly off the main highway (secondary routes).' : 'Focus on the most direct high-scoring Clusters.'}
  `;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
        tools: [{ googleSearch: {} }], // Enable Google Search Grounding
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const result = JSON.parse(text) as Itinerary;

    // Post-processing: Force target arrival dates from user input if the AI missed them
    if (result.stops && data.mandatoryStops.length > 0) {
      result.stops = result.stops.map(stop => {
        const match = data.mandatoryStops.find(ms => 
          stop.city.toLowerCase().includes(ms.location.toLowerCase()) || 
          ms.location.toLowerCase().includes(stop.city.toLowerCase())
        );

        if (match) {
          const userDate = match.arrivalDate || match.date;
          if (userDate) {
            return { ...stop, targetArrivalDate: userDate };
          }
        }
        return stop;
      });
    }

    if (data.startDate) {
        result.startDate = data.startDate;
    }
    result.travelMode = data.travelMode;

    return result;
  } catch (error) {
    console.error("Error generating itinerary:", error);
    throw error;
  }
};

