  const getExactDate = (dayOffset: number): string | null => {
    if (!itinerary.startDate) return null;

    const parts = itinerary.startDate.split('-');
    if (parts.length !== 3) return null;

    const year = parseInt(parts[0], 10);
    const month = parseInt(parts[1], 10) - 1; // JS months are 0-indexed
    const day = parseInt(parts[2], 10);

    // Use UTC to strictly avoid local timezone offsets affecting the date
    const date = new Date(Date.UTC(year, month, day));

    // Add days. Note: Stop Day 1 = Start Date.
    date.setUTCDate(date.getUTCDate() + (dayOffset - 1)); 

    // Format using UTC timezone to ensure stability
    return date.toLocaleDateString('en-US', { 
      weekday: 'short', 
      month: 'short', 
      day: 'numeric',
      year: 'numeric',
      timeZone: 'UTC'
    });
  };

  const getModeIcon = (mode: string | undefined) => {
