};

import React, { useState } from 'react';
import { InputForm } from './components/InputForm';
import { ItineraryDisplay } from './components/ItineraryDisplay';
import { TripFormData, Itinerary } from './types';
import { DEFAULT_FORM_DATA } from './constants';
import { generateItinerary } from './services/geminiService';
import { MapPin, X, AlertCircle, Lightbulb } from 'lucide-react';

const App: React.FC = () => {
  const [itinerary, setItinerary] = useState<Itinerary | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showResultsMobile, setShowResultsMobile] = useState(false);

  const handleGenerate = async (data: TripFormData, isAlternative: boolean) => {
    setIsLoading(true);
    setError(null);

    // Client-side Validation
    if (!data.origin || !data.origin.trim()) {
      setError("Please enter a valid Origin city.");
      setIsLoading(false);
      return;
    }
    if (!data.destination || !data.destination.trim()) {
      setError("Please enter a valid Destination city.");
      setIsLoading(false);
      return;
    }
    if (data.startDate && data.endDate) {
      const start = new Date(data.startDate);
      const end = new Date(data.endDate);
      if (start > end) {
        setError("Start Date cannot be after Return Date.");
        setIsLoading(false);
        return;
      }

      // Check mandatory stops range
      const outOfRangeStop = data.mandatoryStops.find(stop => {
        const dateStr = stop.arrivalDate || stop.date;
        if (!dateStr) return false;
        // String comparison works for YYYY-MM-DD
        return dateStr < data.startDate || dateStr > data.endDate;
      });

      if (outOfRangeStop) {
        setError(`Date for ${outOfRangeStop.location} is outside trip range.`);
        setIsLoading(false);
        return;
      }
    }

    if (window.innerWidth < 1024) {
      setShowResultsMobile(true);
