            <span className="hover:text-gray-800 cursor-pointer transition-colors">Saved Routes</span>
            <span className="hover:text-gray-800 cursor-pointer transition-colors">Market Insights</span>
          </div>

          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-full bg-gray-100 border border-gray-200 flex items-center justify-center text-gray-500 hover:shadow-md transition-shadow cursor-pointer">
