import { GoogleGenAI, Type, Schema } from "@google/genai";
import { TripFormData, Itinerary, TravelMode } from "../types";
import { GEMINI_MODEL } from "../constants";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

const KEYWORD_MARKET_DATA = `
MARKET DEMAND CONTEXT (Baseline Niche Data):
Use this data to determine the "Niche Relevance" of a city.
1. gay massage - High Interest
2. sensual massage - High Interest
3. male massage therapist - Moderate Interest
4. LGBTQ friendly massage - Moderate Interest
`;

const itinerarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    routeName: { type: Type.STRING, description: "A catchy name for this route" },
    totalDistance: { type: Type.STRING, description: "Estimated total distance" },
    totalDuration: { type: Type.STRING, description: "Estimated total travel duration including stay nights" },
    summary: { type: Type.STRING, description: "A brief summary of why this route is profitable/good, referencing real-world events or trends found via Search." },
    stops: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day: { type: Type.INTEGER },
          city: { type: Type.STRING },
          description: { type: Type.STRING, description: "Why this stop is profitable. Cite specific real-world factors (events, popularity) found via Search." },
          demandScore: { type: Type.INTEGER, description: "The calculated Opportunity Score (0-100) using the V, T, D, S, E, P, G formula." },
          trendVelocity: { type: Type.STRING, description: "A short indicator of interest growth (e.g. '🔥 Exploding', '📈 Rising', '➡️ Stable', '📉 Cooling')." },
          nightsToStay: { type: Type.INTEGER, description: "Recommended nights based on calibrated probability" },
          travelToNext: { type: Type.STRING, description: "Time to next stop or destination" },
          transportMode: { type: Type.STRING, description: "The specific mode of transport to reach the NEXT stop (Car, Bus, Plane)" },
          targetArrivalDate: { type: Type.STRING, description: "If the user requested a specific date, reflect it here (YYYY-MM-DD)." },
          trafficCondition: { type: Type.STRING, description: "Estimated typical traffic conditions for this leg." },
          activity: { type: Type.STRING, description: "Recommended activity matching the keywords" },
          coordinates: {
             type: Type.OBJECT,
             properties: {
                lat: { type: Type.NUMBER },
                lng: { type: Type.NUMBER }
             }
          }
        },
        required: ["day", "city", "description", "demandScore", "trendVelocity", "nightsToStay", "travelToNext", "activity"],
      },
    },
  },
  required: ["routeName", "totalDistance", "totalDuration", "stops", "summary"],
};

export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();

  const mandatoryStopsText = data.mandatoryStops
    .map(s => {
      let info = s.location;
      const dateVal = s.arrivalDate || s.date;
      if (dateVal) info += ` (Must arrive on: ${dateVal})`;
      if (s.nights) info += ` (Stay: ${s.nights} nights)`;
      return info;
    })
    .join(', ');

  const destinationText = data.destinationDate 
    ? `${data.destination} (Target Arrival: ${data.destinationDate})` 
    : data.destination;

  let modeText: string = data.travelMode;
  if (data.travelMode === TravelMode.Mixed && data.travelModeDetail) {
    modeText = `${TravelMode.Mixed}: ${data.travelModeDetail}`;
  }

  const prompt = `
    Act as a high-precision algorithmic engine for a professional Male Massage Therapist.
    Plan a profitable road trip from ${data.origin} to ${destinationText}.

    Context:
    - Mode: ${modeText}
    - Max Drive: ${data.maxDriveHours}h/day.
    - Dates: ${data.startDate || 'TBD'} to ${data.endDate || 'TBD'}.
    - Mandatory Stops: ${mandatoryStopsText}.

    ${KEYWORD_MARKET_DATA}

    YOU MUST EXECUTE THE FOLLOWING 5-STEP ALGORITHM STRICTLY (The "Contract of Truth"):

    =========================================
    STEP 1: DATA GATHERING & GROUNDING (CRITICAL)
    =========================================
    **YOU MUST USE GOOGLE SEARCH** to determine the validity and metrics for potential stops.
    For each potential city in the corridor:
    1. Search "monthly search volume [keyword] [city]" -> Estimate Volume (V).
    2. Search "Google Trends interest [city] [keyword]" -> Estimate Trend Index (T) 0-100.
    3. Search "recent trends/growth [city] nightlife/wellness" -> Estimate Velocity (D) as % growth.
    4. Calculate Geography (Desvio) as the % detour from the direct route.

    =========================================
    STEP 2: THE "HARD GATE" (GATE DURO)
    =========================================
    You must **DISCARD** any potential stop (unless explicitly Mandatory by user) that fails ANY of these conditions:

    1. **Volume (V)** < 1000 (Monthly Searches)
    2. **Trend (T)** < 20 (Google Trends Index 0-100)
    3. **Velocity (D)** < 0.10 (+10% Growth Year-over-Year or Month-over-Month)
    4. **Geography (Desvio)** > 0.15 (Detour adds >15% to total trip distance)

    **IF A CITY FAILS THIS GATE, IT MUST NOT BE IN THE ITINERARY.**

    =========================================
    STEP 3: OPPORTUNITY SCORE (0-100)
    =========================================
    For cities that pass the Gate, calculate the precise score using this formula:

    **Score = 0.30*Vn + 0.25*Tn + 0.15*Dn + 0.10*Sn + 0.10*En + 0.05*Pn + 0.05*Gn**

    Where (Normalize all values to 0.0 - 1.0):
    - **Vn (Volume)**: CLAMP(V / 5000, 0, 1). (Target: 5000+ searches = 1.0)
    - **Tn (Trend)**: CLAMP(T / 100, 0, 1). (Target: Index 100 = 1.0)
    - **Dn (Velocity)**: CLAMP(D / 0.50, 0, 1). (Target: 50% growth = 1.0)
    - **Sn (Supply/Venues)**: CLAMP(CountOfVenues / 5, 0, 1). (Target: 5+ relevant venues = 1.0)
    - **En (Events)**: 1.0 if Major Event during dates, 0.5 if Minor, 0 if None.
    - **Pn (Power/Price)**: 1.0 if High Spending Power/Rates, 0.5 if Med, 0.2 if Low.
    - **Gn (Geography)**: 1.0 - CLAMP(Desvio, 0, 1). (Direct route = 1.0).

    Multiply final sum by 100 to get the 0-100 Score.

    =========================================
    STEP 4: PROBABILITY CALIBRATION (CONVERSION)
    =========================================
    Convert Score to Nights:
    - Score < 40: SKIP (Probability too low).
    - Score 40 - 59: 1 Night.
    - Score 60 - 84: 2 Nights.
    - Score >= 85: 3 Nights (High Confidence).

    =========================================
    STEP 5: ROUTE ENGINE OUTPUT
    =========================================
    - Sequence the valid clusters/stops logically.
    - Respect specific arrival dates if provided.
    - Provide estimated traffic conditions.
    - Return JSON matching the schema.

    ${isAlternative ? 'Focus on high-scoring Clusters that are slightly off the main highway (secondary routes).' : 'Focus on the most direct high-scoring Clusters.'}
  `;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
        tools: [{ googleSearch: {} }], // Enable Google Search Grounding
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const result = JSON.parse(text) as Itinerary;

    // Post-processing: Force target arrival dates from user input if the AI missed them
    if (result.stops && data.mandatoryStops.length > 0) {
      result.stops = result.stops.map(stop => {
        const match = data.mandatoryStops.find(ms => 
          stop.city.toLowerCase().includes(ms.location.toLowerCase()) || 
          ms.location.toLowerCase().includes(stop.city.toLowerCase())
        );

        if (match) {
          const userDate = match.arrivalDate || match.date;
          if (userDate) {
            return { ...stop, targetArrivalDate: userDate };
          }
        }
        return stop;
      });
    }

    if (data.startDate) {
        result.startDate = data.startDate;
    }
    result.travelMode = data.travelMode;

    return result;
  } catch (error) {
    console.error("Error generating itinerary:", error);
    throw error;
  }
};

