export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();

  const mandatoryStopsText = data.mandatoryStops
    .map(s => {
      let info = s.location;
      const dateVal = s.arrivalDate || s.date;
      if (dateVal) info += ` (Must arrive on: ${dateVal})`;
      if (s.nights) info += ` (Stay: ${s.nights} nights)`;
      return info;
    })
    .join(', ');

  const destinationText = data.destinationDate 
    ? `${data.destination} (Target Arrival: ${data.destinationDate})` 
    : data.destination;

  let modeText: string = data.travelMode;
  if (data.travelMode === TravelMode.Mixed && data.travelModeDetail) {
    modeText = `${TravelMode.Mixed}: ${data.travelModeDetail}`;
  }

  const prompt = `
    Act as a high-precision algorithmic engine for a professional Male Massage Therapist.
    Plan a profitable road trip from ${data.origin} to ${destinationText}.

    Context:
    - Mode: ${modeText}
    - Max Drive: ${data.maxDriveHours}h/day.
    - Dates: ${data.startDate || 'TBD'} to ${data.endDate || 'TBD'}.
    - Mandatory Stops: ${mandatoryStopsText}.

    ${KEYWORD_MARKET_DATA}

    YOU MUST EXECUTE THE FOLLOWING 5-STEP ALGORITHM STRICTLY (The "Contract of Truth"):

    =========================================
    STEP 1: DATA GATHERING & GROUNDING (CRITICAL)
    =========================================
    **YOU MUST USE GOOGLE SEARCH** to determine the validity and metrics for potential stops.
    For each potential city in the corridor, execute these specific searches:

    1. **Volume (V)**: Search "monthly search volume [keyword] [city]".
    2. **Trend (T)**: Search "Google Trends interest [city] [keyword]".
    3. **Velocity (D)**: Search "recent trends/growth [city] nightlife/wellness".
    4. **Supply/Venues (Sn)**: Search "number of gay spas/clubs [city]" or "massage competition [city]".
    5. **Events (En)**: Search "major events [city] [travel month]" (e.g., Pride, Festivals, Conferences).
    6. **Power/Econ (Pn)**: Search "cost of living [city]" or "average hotel price [city]" to gauge spending power.
    7. **Geography**: Calculate detour % from direct route.

    =========================================
    STEP 2: CLUSTERING (ADC LOGIC) & THE "HARD GATE"
    =========================================
    **Area Demand Cluster (ADC) Aggregation Logic:**
    You must calculate the **"Cluster Volume"** and **"Cluster Trend"** by aggregating data from the Anchor City and its nearby Satellite Cities (within 60 mins).

    **CRITICAL MATHEMATICAL FORMULA FOR AGGREGATION:**
    Apply a decay factor to satellite cities based on travel time to the anchor:

    > **weight_distance = exp( -tempo_em_min / 45 )**

    Where 'tempo_em_min' is travel time in minutes from the satellite to the anchor.
    1. **Cluster Volume** = Sum( City_Volume * weight_distance ) for all cities in cluster.
    2. **Cluster Trend** = Weighted Average of trends using 'weight_distance'.

    *Goal: Use this aggregated "Cluster Volume" to save smaller cities that are close to major hubs from being discarded.*

    **Gate Duro (Hard Gate):**
    After clustering, you must **DISCARD** any potential stop (or Cluster) that fails ANY of these conditions:
    1. **Volume (V)** < 1000 (Monthly Searches - Use Aggregated Cluster Volume)
    2. **Trend (T)** < 20 (Google Trends Index 0-100)
    3. **Velocity (D)** < 0.10 (+10% Growth)
    4. **Geography** > 0.15 (Detour > 15%)

    =========================================
    STEP 3: OPPORTUNITY SCORE (0-100)
    =========================================
    Calculate score using: **Score = 0.30*Vn + 0.25*Tn + 0.15*Dn + 0.10*Sn + 0.10*En + 0.05*Pn + 0.05*Gn**

    Normalize using data found in Step 1 & 2:
    - **Vn**: CLAMP(Cluster_Volume / 5000, 0, 1).
    - **Tn**: CLAMP(Cluster_Trend / 100, 0, 1).
    - **Dn**: CLAMP(D / 0.50, 0, 1).
    - **Sn (Supply)**: CLAMP(CountOfVenues / 5, 0, 1). (Target: 5+ relevant venues/spas found = 1.0).
    - **En (Events)**: 1.0 if Major Event found during dates, 0.5 if Minor, 0 if None.
    - **Pn (Power)**: 1.0 if High Hotel Prices/GDP found, 0.5 if Med, 0.2 if Low.
    - **Gn (Geo)**: 1.0 - CLAMP(Detour, 0, 1).

    =========================================
    STEP 4: PROBABILITY CALIBRATION
    =========================================
    - Score < 40: SKIP.
    - Score 40-59: 1 Night.
    - Score 60-84: 2 Nights.
    - Score >= 85: 3 Nights.

    =========================================
    STEP 5: ROUTE ENGINE OUTPUT
    =========================================
    - Sequence stops logically.
    - Include 'clusterInfo' (Anchor + Volume) in the output.
    - Return JSON matching the schema.

    ${isAlternative ? 'Focus on high-scoring Clusters that are slightly off the main highway (secondary routes).' : 'Focus on the most direct high-scoring Clusters.'}
  `;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
        tools: [{ googleSearch: {} }], // Enable Google Search Grounding
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const result = JSON.parse(text) as Itinerary;

    // Post-processing: Force target arrival dates from user input if the AI missed them
    if (result.stops && data.mandatoryStops.length > 0) {
      result.stops = result.stops.map(stop => {
        const match = data.mandatoryStops.find(ms => 
          stop.city.toLowerCase().includes(ms.location.toLowerCase()) || 
          ms.location.toLowerCase().includes(stop.city.toLowerCase())
        );

        if (match) {
          const userDate = match.arrivalDate || match.date;
          if (userDate) {
            return { ...stop, targetArrivalDate: userDate };
          }
        }
        return stop;
      });
    }

    if (data.startDate) {
        result.startDate = data.startDate;
    }
    result.travelMode = data.travelMode;

    return result;
  } catch (error) {
    console.error("Error generating itinerary:", error);
    throw error;
  }
};

