import React, { useState, useEffect } from 'react';
import { Plus, X, MapPin, Calendar, Clock, Car, Bus, Plane, Shuffle, Search, Minus, Info, Edit2, Check, ChevronDown, ChevronUp, AlertCircle, Sparkles } from 'lucide-react';
import { TripFormData, TravelMode, MandatoryStop, ValidationErrors } from '../types';
import { DEFAULT_FORM_DATA } from '../constants';

interface InputFormProps {
  initialData: TripFormData;
  onSubmit: (data: TripFormData, isAlternative: boolean) => void;
  isLoading: boolean;
  validationErrors?: ValidationErrors;
}

const STORAGE_KEY = 'roadTripPro_formData';

export const InputForm: React.FC<InputFormProps> = ({ initialData, onSubmit, isLoading, validationErrors }) => {
  // Initialize state from localStorage or fall back to initialData
  const [formData, setFormData] = useState<TripFormData>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : initialData;
    } catch (e) {
      console.warn('Failed to load form data from local storage', e);
      return initialData;
    }
  });

  const [editingStopIndex, setEditingStopIndex] = useState<number | null>(null);

  // Persist to localStorage whenever formData changes
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(formData));
    } catch (e) {
      console.warn('Failed to save form data to local storage', e);
    }
  }, [formData]);

  const handleChange = (field: keyof TripFormData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleStopChange = (index: number, field: keyof MandatoryStop, value: string | number) => {
    const newStops = [...formData.mandatoryStops];
    // Cast appropriately if updating numeric fields
    const updatedValue = field === 'nights' ? Number(value) : value;
    newStops[index] = { ...newStops[index], [field]: updatedValue };
    handleChange('mandatoryStops', newStops);
  };

  const addStop = () => {
    const newIndex = formData.mandatoryStops.length;
    handleChange('mandatoryStops', [...formData.mandatoryStops, { location: '', date: '', arrivalDate: '', nights: 1 }]);
    setEditingStopIndex(newIndex); // Auto-open edit mode for new stop
  };

  const removeStop = (index: number) => {
    const newStops = formData.mandatoryStops.filter((_, i) => i !== index);
    handleChange('mandatoryStops', newStops);
    if (editingStopIndex === index) setEditingStopIndex(null);
  };

  const toggleEditStop = (index: number) => {
    if (editingStopIndex === index) {
      setEditingStopIndex(null); // Save/Close
    } else {
      setEditingStopIndex(index); // Open
    }
  };

  const getModeIcon = (mode: string) => {
    switch (mode) {
      case TravelMode.Car: return <Car className="w-5 h-5" />;
      case TravelMode.Bus: return <Bus className="w-5 h-5" />;
      case TravelMode.Plane: return <Plane className="w-5 h-5" />;
      default: return <Shuffle className="w-5 h-5" />;
    }
  };

  const renderError = (fieldName: string) => {
      if (!validationErrors || !validationErrors[fieldName]) return null;
      const err = validationErrors[fieldName];
      return (
          <div className="mt-2 flex items-start gap-2 animate-in slide-in-from-top-1 fade-in duration-300">
             <div className="min-w-[4px] h-full bg-red-400 rounded-full mt-1"></div>
             <div>
                <p className="text-xs font-bold text-red-600 leading-tight">{err.message}</p>
                <p className="text-[10px] text-red-400 font-medium mt-0.5 flex items-center gap-1">
                  <Sparkles className="w-3 h-3" />
                  {err.suggestion}
                </p>
             </div>
          </div>
      );
  };

  const getInputClass = (fieldName: string, baseClass: string) => {
      const hasError = validationErrors && validationErrors[fieldName];
      return `${baseClass} ${hasError ? 'bg-red-50/50 text-red-900 placeholder-red-300' : 'bg-transparent text-gray-900 placeholder-gray-400'}`;
  };

  const getContainerClass = (fieldName: string, baseClass: string) => {
       const hasError = validationErrors && validationErrors[fieldName];
       return `${baseClass} ${hasError ? 'bg-red-50 border-red-200' : ''}`;
  };

  return (
    <div className="h-full flex flex-col bg-white">
      <div className="p-6 pb-2 border-b border-gray-100 lg:border-none">
        <h2 className="text-2xl font-bold text-gray-800">Where to?</h2>
        <p className="text-gray-500 text-sm mt-1">Configure your professional road trip</p>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
        {/* Origin & Destination Card */}
        <div className={`bg-white border rounded-2xl shadow-[0_6px_16px_rgba(0,0,0,0.08)] overflow-hidden transition-colors border-gray-200`}>
          {/* Origin */}
          <div className={getContainerClass('origin', 'relative p-4 border-b border-gray-100 hover:bg-gray-50 transition-colors')}>
            <label className={`text-[10px] font-bold uppercase tracking-wider block mb-1 ${validationErrors?.origin ? 'text-red-500' : 'text-gray-500'}`}>Origin</label>
            <input
              type="text"
              value={formData.origin}
              onChange={(e) => handleChange('origin', e.target.value)}
              className={getInputClass('origin', "w-full font-semibold text-lg focus:outline-none")}
              placeholder="Where are you starting?"
            />
            <div className="absolute right-4 top-1/2 -translate-y-1/2 flex items-center gap-2">
                 {validationErrors?.origin ? <AlertCircle className="w-5 h-5 text-red-500" /> : <MapPin className="w-5 h-5 text-gray-400" />}
            </div>
            {renderError('origin')}
          </div>

          {/* Destination */}
          <div className={getContainerClass('destination', 'relative p-4 hover:bg-gray-50 transition-colors')}>
            <label className={`text-[10px] font-bold uppercase tracking-wider block mb-1 ${validationErrors?.destination ? 'text-red-500' : 'text-gray-500'}`}>Destination</label>
            <input
              type="text"
              value={formData.destination}
              onChange={(e) => handleChange('destination', e.target.value)}
              className={getInputClass('destination', "w-full font-semibold text-lg focus:outline-none")}
              placeholder="Where are you going?"
            />
             <div className="absolute right-4 top-1/2 -translate-y-1/2 flex items-center gap-2">
                 {validationErrors?.destination ? <AlertCircle className="w-5 h-5 text-red-500" /> : <MapPin className="w-5 h-5 text-gray-400" />}
            </div>
             {renderError('destination')}
          </div>
           {/* Destination Date */}
           <div className="relative p-4 border-t border-gray-100 hover:bg-gray-50 transition-colors bg-gray-50/50">
            <label className="text-[10px] font-bold uppercase tracking-wider text-gray-500 block mb-1">Target Arrival Date (Optional)</label>
            <input
              type="date"
              value={formData.destinationDate}
              onChange={(e) => handleChange('destinationDate', e.target.value)}
              className="w-full bg-transparent text-gray-700 font-medium focus:outline-none text-base appearance-none min-h-[44px]"
            />
          </div>
        </div>

