import React, { useState } from 'react';
import { InputForm } from './components/InputForm';
import { ItineraryDisplay } from './components/ItineraryDisplay';
import { MarketInsights } from './components/MarketInsights';
import { TripFormData, Itinerary, MarketInsight, ValidationErrors } from './types';
import { DEFAULT_FORM_DATA } from './constants';
import { generateItinerary, generateMarketInsights } from './services/geminiService';
import { MapPin, X, AlertCircle, Lightbulb, TrendingUp, Compass } from 'lucide-react';

type ViewMode = 'planner' | 'insights';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewMode>('planner');

  // Itinerary State
  const [itinerary, setItinerary] = useState<Itinerary | null>(null);
  const [isItineraryLoading, setIsItineraryLoading] = useState(false);
  const [itineraryError, setItineraryError] = useState<string | null>(null);
  const [validationErrors, setValidationErrors] = useState<ValidationErrors>({});
  const [showResultsMobile, setShowResultsMobile] = useState(false);

  // Insights State
  const [insights, setInsights] = useState<MarketInsight | null>(null);
  const [isInsightsLoading, setIsInsightsLoading] = useState(false);

  const handleFetchInsights = async () => {
    setIsInsightsLoading(true);
    try {
        const result = await generateMarketInsights();
        setInsights(result);
    } catch (e) {
        console.error("Failed to fetch insights");
    } finally {
        setIsInsightsLoading(false);
    }
  };

  // Switch tabs
  const switchView = (view: ViewMode) => {
      setCurrentView(view);
      if (view === 'insights' && !insights && !isInsightsLoading) {
          handleFetchInsights();
      }
  };

  const handleGenerate = async (data: TripFormData, isAlternative: boolean) => {
    setIsItineraryLoading(true);
    setItineraryError(null);
    setValidationErrors({});

    // Client-side Validation (Populate ValidationErrors)
    const errors: ValidationErrors = {};

    if (!data.origin || !data.origin.trim()) {
      errors.origin = { message: "Origin is required", suggestion: "Enter a starting city (e.g., 'New York, NY')" };
    }
    if (!data.destination || !data.destination.trim()) {
      errors.destination = { message: "Destination is required", suggestion: "Enter a destination city" };
    }
    if (data.startDate && data.endDate) {
      const start = new Date(data.startDate);
      const end = new Date(data.endDate);
      if (start > end) {
         errors.startDate = { message: "Invalid date range", suggestion: "Start date must be before Return date" };
         errors.endDate = { message: "Invalid date range", suggestion: "Return date must be after Start date" };
      }
    }

    if (Object.keys(errors).length > 0) {
        setValidationErrors(errors);
        setIsItineraryLoading(false);
        return;
    }

    if (window.innerWidth < 1024) {
      setShowResultsMobile(true);
    }
    try {
      const result = await generateItinerary(data, isAlternative);
      setItinerary(result);
    } catch (err: any) {
      setItineraryError(err.message || "Failed to generate itinerary. Please try again.");
    } finally {
      setIsItineraryLoading(false);
    }
  };

  // Legacy Error Display logic for general API errors (not field specific)
  const getErrorDetails = (errorMessage: string) => {
    const lowerMsg = errorMessage.toLowerCase();

    if (lowerMsg.includes('api') || lowerMsg.includes('key') || lowerMsg.includes('quota') || lowerMsg.includes('network')) {
      return {
        title: "Connection or Service Issue",
        suggestions: [
          "Check your internet connection.",
          "The AI service might be experiencing high traffic.",
          "Verify your API key configuration."
        ]
      };
    }

    // Default catch-all
    return {
      title: "Planning Interrupted",
      suggestions: [
        "Try increasing 'Max Drive Hours' to open up more routes.",
        "Reduce constraints or mandatory stops to simplify the request.",
        "Try generating the plan again in a few moments."
      ]
    };
  };

  return (
    <div className="flex flex-col h-screen bg-gray-50 text-[#222222] font-sans">
      {/* Navbar - Airbnb Style */}
      <header className="flex-none bg-white border-b border-gray-200 z-50 sticky top-0 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-2 text-[#FF385C] cursor-pointer" onClick={() => setCurrentView('planner')}>
            <MapPin className="w-8 h-8 fill-current" />
            <h1 className="text-2xl font-bold tracking-tight text-[#FF385C] hidden sm:block">
              RoadTripPro
            </h1>
          </div>

          <div className="flex items-center gap-6 text-sm font-semibold text-gray-500">
            <button 
                onClick={() => switchView('planner')}
                className={`py-2 transition-colors flex items-center gap-2 ${currentView === 'planner' ? 'text-gray-900 border-b-2 border-gray-900' : 'hover:text-gray-800'}`}
            >
                <Compass className="w-4 h-4" />
                Plan a Trip
            </button>
            <button 
                onClick={() => switchView('insights')}
                className={`py-2 transition-colors flex items-center gap-2 ${currentView === 'insights' ? 'text-gray-900 border-b-2 border-gray-900' : 'hover:text-gray-800'}`}
            >
                <TrendingUp className="w-4 h-4" />
                Market Insights
            </button>
          </div>

          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-full bg-gray-100 border border-gray-200 flex items-center justify-center text-gray-500 hover:shadow-md transition-shadow cursor-pointer">
                <span className="text-xs font-bold">JD</span>
             </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-hidden relative">
        <div className="max-w-7xl mx-auto h-full p-0 lg:p-6">

          {currentView === 'planner' ? (
             <div className="flex flex-col lg:flex-row gap-8 h-full">
                {/* Left Panel: Inputs */}
                <div className={`w-full lg:w-[400px] flex-none h-full bg-white lg:rounded-2xl lg:shadow-xl lg:border lg:border-gray-100 overflow-hidden flex flex-col z-20 transition-transform duration-300 ${showResultsMobile ? '-translate-x-full absolute' : 'translate-x-0 relative'} lg:translate-x-0 lg:relative`}>
                    <InputForm 
                    initialData={DEFAULT_FORM_DATA} 
                    onSubmit={handleGenerate}
                    isLoading={isItineraryLoading}
                    validationErrors={validationErrors}
                    />

                    {/* General API Error Box */}
                    {itineraryError && (
                    <div className="mx-6 mb-6 relative overflow-hidden rounded-xl bg-red-50 border border-red-100 shadow-sm animate-in fade-in slide-in-from-top-2">
                        <div className="absolute left-0 top-0 bottom-0 w-1 bg-red-500"></div>
                        <div className="p-4">
                        <div className="flex items-start gap-3">
                            <div className="flex-shrink-0 mt-0.5">
                            <AlertCircle className="w-5 h-5 text-red-600" />
                            </div>
                            <div className="flex-1">
                            <h3 className="text-sm font-bold text-red-900 mb-1">
                                {getErrorDetails(itineraryError).title}
                            </h3>
                            <p className="text-sm text-red-800 leading-relaxed font-medium mb-3">
                                {itineraryError}
                            </p>

                            <div className="bg-white/60 rounded-lg p-3 border border-red-100">
                                <div className="flex items-center gap-2 mb-2 text-red-900/70 text-xs font-bold uppercase tracking-wider">
                                <Lightbulb className="w-3 h-3" />
                                <span>Try This</span>
                                </div>
                                <ul className="space-y-1.5">
                                {getErrorDetails(itineraryError).suggestions.map((suggestion, idx) => (
                                    <li key={idx} className="text-xs text-red-700 flex items-start gap-2">
                                    <span className="mt-1.5 w-1 h-1 rounded-full bg-red-400 flex-shrink-0"></span>
                                    <span className="leading-snug">{suggestion}</span>
                                    </li>
                                ))}
                                </ul>
                            </div>
                            </div>
                            <button 
                            onClick={() => setItineraryError(null)}
                            className="flex-shrink-0 -mr-1 -mt-1 p-2 text-red-400 hover:text-red-700 hover:bg-red-100 rounded-full transition-all"
                            >
                            <X className="w-4 h-4" />
                            </button>
                        </div>
                        </div>
                    </div>
                    )}
                </div>

                {/* Right Panel: Display */}
                <div className={`flex-1 h-full overflow-hidden bg-white lg:bg-transparent rounded-none lg:rounded-2xl relative transition-transform duration-300 ${showResultsMobile ? 'translate-x-0 absolute inset-0 z-30' : 'translate-x-full absolute'} lg:translate-x-0 lg:relative lg:inset-auto lg:z-0`}>

                    {/* Mobile Back Button */}
                    <div className="lg:hidden absolute top-4 left-4 z-50">
                        <button 
                        onClick={() => setShowResultsMobile(false)}
                        className="bg-white p-2 rounded-full shadow-lg border border-gray-100 text-gray-700 font-bold text-sm px-4"
                        >
                        ← Edit Plan
                        </button>
                    </div>

                    <ItineraryDisplay itinerary={itinerary} isLoading={isItineraryLoading} />
                </div>
             </div>
          ) : (
             <div className="h-full bg-transparent">
                 <MarketInsights insights={insights} isLoading={isInsightsLoading} onRefresh={handleFetchInsights} />
             </div>
          )}

        </div>
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { TripFormData, Itinerary, TravelMode, MarketInsight } from "../types";
import { GEMINI_MODEL } from "../constants";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

const KEYWORD_MARKET_DATA = `
MARKET DEMAND CONTEXT (Baseline Niche Data):
Use this data to determine the "Niche Relevance" of a city.
1. gay massage - High Interest
2. sensual massage - High Interest
3. male massage therapist - Moderate Interest
4. LGBTQ friendly massage - Moderate Interest
`;

const itinerarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    routeName: { type: Type.STRING, description: "A catchy name for this route" },
    totalDistance: { type: Type.STRING, description: "Estimated total distance" },
    totalDuration: { type: Type.STRING, description: "Estimated total travel duration including stay nights" },
    summary: { type: Type.STRING, description: "A brief summary of why this route is profitable/good, referencing real-world events or trends found via Search." },
    stops: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day: { type: Type.INTEGER },
          city: { type: Type.STRING },
          description: { type: Type.STRING, description: "Why this stop is profitable. Cite specific real-world factors (events, popularity) found via Search." },
          demandScore: { type: Type.INTEGER, description: "The calculated Opportunity Score (0-100) using the V, T, D, S, E, P, G formula." },
          trendVelocity: { type: Type.STRING, description: "A short indicator of interest growth (e.g. '🔥 Exploding', '📈 Rising', '➡️ Stable', '📉 Cooling')." },
          clusterInfo: {
            type: Type.OBJECT,
            description: "Information about the Area Demand Cluster (ADC) this stop belongs to.",
            properties: {
                anchorCity: { type: Type.STRING, description: "The main hub city for this area cluster." },
                clusterVolume: { type: Type.STRING, description: "Aggregated monthly search volume for the entire cluster area (e.g. '15k+')." }
            }
          },
          nightsToStay: { type: Type.INTEGER, description: "Recommended nights based on calibrated probability" },
          travelToNext: { type: Type.STRING, description: "Time to next stop or destination" },
          transportMode: { type: Type.STRING, description: "The specific mode of transport to reach the NEXT stop (Car, Bus, Plane)" },
          targetArrivalDate: { type: Type.STRING, description: "If the user requested a specific date, reflect it here (YYYY-MM-DD)." },
          trafficCondition: { type: Type.STRING, description: "Estimated typical traffic conditions for this leg." },
          activity: { type: Type.STRING, description: "Recommended activity matching the keywords" },
          coordinates: {
             type: Type.OBJECT,
             properties: {
                lat: { type: Type.NUMBER },
                lng: { type: Type.NUMBER }
             }
          }
        },
        required: ["day", "city", "description", "demandScore", "trendVelocity", "nightsToStay", "travelToNext", "activity"],
      },
    },
  },
  required: ["routeName", "totalDistance", "totalDuration", "stops", "summary"],
};

const marketInsightSchema: Schema = {
    type: Type.OBJECT,
    properties: {
        trendingKeywords: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    keyword: { type: Type.STRING },
                    volume: { type: Type.INTEGER, description: "Estimated monthly search volume (100-10000+)" },
                    growth: { type: Type.STRING, description: "Growth percentage or label e.g. '+20%', 'Stable'" }
                }
            }
        },
        topClusters: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    city: { type: Type.STRING },
                    score: { type: Type.INTEGER, description: "Opportunity score 0-100" },
                    tags: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
            }
        },
        seasonalAdvice: { type: Type.STRING, description: "Strategic advice for the current season." },
        lastUpdated: { type: Type.STRING, description: "Current date formatted." }
    },
