export const ItineraryDisplay: React.FC<ItineraryDisplayProps> = ({ itinerary, isLoading }) => {
  const [expandedStopIndex, setExpandedStopIndex] = useState<number | null>(null);

  if (isLoading) {
    return <SkeletonLoader />;
  }

  if (!itinerary) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-8 bg-gray-50/50 rounded-2xl border-2 border-dashed border-gray-200 lg:mr-6 lg:mt-6">
        <div className="bg-white p-6 rounded-full shadow-lg mb-6">
           <Map className="w-12 h-12 text-[#FF385C]" />
        </div>
        <h3 className="text-2xl font-bold text-gray-800 mb-3">Ready to Plan?</h3>
        <p className="max-w-md text-gray-500 leading-relaxed">
          Configure your trip on the left and tap <span className="font-bold text-gray-900">"Explore Plan"</span>. We'll find the most profitable stops for your journey.
        </p>
      </div>
    );
  }

  if (itinerary.stops.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-8 bg-gray-50/50 rounded-2xl border-2 border-dashed border-gray-200 lg:mr-6 lg:mt-6">
        <div className="bg-white p-6 rounded-full shadow-lg mb-6">
           <AlertTriangle className="w-12 h-12 text-yellow-500" />
        </div>
        <h3 className="text-2xl font-bold text-gray-800 mb-3">No Viable Stops Found</h3>
        <p className="max-w-md text-gray-500 leading-relaxed mb-6">
          We analyzed the route but couldn't identify stops that meet your profitability criteria or constraints.
        </p>
        <div className="bg-white border border-gray-200 rounded-xl p-6 max-w-lg w-full shadow-sm text-left">
           <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">AI Analysis</h4>
           <p className="text-sm text-gray-700 leading-relaxed">
             {itinerary.summary || "Try adjusting your travel dates, increasing max drive hours, or changing your route to find better opportunities."}
           </p>
        </div>
      </div>
    );
  }

  const toggleExpand = (index: number) => {
    setExpandedStopIndex(expandedStopIndex === index ? null : index);
  };

  // Robust Date Calculation handling UTC to avoid timezone shifts
  const getExactDate = (dayOffset: number): string | null => {
    if (!itinerary.startDate) return null;

    // Parse YYYY-MM-DD safely
    const parts = itinerary.startDate.split('-').map(Number);
    if (parts.length !== 3 || parts.some(isNaN)) return null;

    const [year, month, day] = parts;

    // Create a base date object in UTC.
    // We set the time to 12:00:00 (Noon) to act as a buffer against any potential 
    // boundary issues, although strict UTC arithmetic is safe.
    // Month is 0-indexed in JS Date constructor.
    const date = new Date(Date.UTC(year, month - 1, day, 12, 0, 0));

    // Add the offset (Day 1 corresponds to the start date, so add 0 days if offset is 1)
    // using setUTCDate handles month/year rollovers automatically (e.g. Jan 31 + 1 day = Feb 1)
    date.setUTCDate(date.getUTCDate() + Math.floor(dayOffset - 1));

    // Format specifically in UTC to ensure "Day 1" is always "Start Date" 
    // regardless of the user's browser timezone (e.g. user in Tokyo planning US trip).
    return date.toLocaleDateString('en-US', { 
      weekday: 'short', 
      month: 'short', 
      day: 'numeric',
      year: 'numeric',
      timeZone: 'UTC'
    });
  };

  const getModeIcon = (mode: string | undefined) => {
    const normalizeMode = mode?.toLowerCase() || '';
    if (normalizeMode.includes('car')) return <Car className="w-5 h-5" />;
    if (normalizeMode.includes('bus')) return <Bus className="w-5 h-5" />;
    if (normalizeMode.includes('plane') || normalizeMode.includes('flight')) return <Plane className="w-5 h-5" />;
    if (normalizeMode.includes('mixed')) return <Shuffle className="w-5 h-5" />;
    return <Navigation className="w-5 h-5" />;
  };

  const getMapsTrafficLink = (originCity: string, destinationCity: string) => {
    const origin = encodeURIComponent(originCity);
    const dest = encodeURIComponent(destinationCity);
    return `https://www.google.com/maps/dir/?api=1&origin=${origin}&destination=${dest}&travelmode=driving&layer=t`;
  };

  return (
    <div className="h-full overflow-y-auto px-4 pb-12 lg:pr-6 custom-scrollbar">
      {/* Hero Header */}
      <div className="bg-white rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.06)] border border-gray-100 overflow-hidden mb-8 mt-2 lg:mt-6">
        <div className="bg-gradient-to-r from-[#FF385C] to-[#E00B41] h-32 relative">
             <div className="absolute -bottom-10 right-8 bg-white p-4 rounded-2xl shadow-lg border border-gray-100">
                <div className="text-center">
                    <p className="text-[10px] uppercase font-bold text-gray-400">Total Profitability</p>
                    <div className="flex items-center gap-1 justify-center">
                        <Star className="w-5 h-5 text-yellow-400 fill-yellow-400" />
                        <span className="text-2xl font-black text-gray-900">High</span>
                    </div>
                </div>
             </div>
        </div>
        <div className="px-8 pt-6 pb-8">
            <h2 className="text-3xl font-extrabold text-gray-900 mb-2">{itinerary.routeName}</h2>
            <p className="text-gray-500 text-lg leading-relaxed mb-6 max-w-2xl">{itinerary.summary}</p>

            <div className="flex flex-wrap gap-3">
                <div className="px-4 py-2 bg-gray-50 rounded-full border border-gray-200 flex items-center gap-2 text-sm font-semibold text-gray-700">
                    <Navigation className="w-4 h-4 text-[#FF385C]" />
                    {itinerary.totalDistance}
                </div>
                 <div className="px-4 py-2 bg-gray-50 rounded-full border border-gray-200 flex items-center gap-2 text-sm font-semibold text-gray-700">
                    <Clock className="w-4 h-4 text-[#FF385C]" />
                    {itinerary.totalDuration}
                </div>
                 <div className="px-4 py-2 bg-gray-50 rounded-full border border-gray-200 flex items-center gap-2 text-sm font-semibold text-gray-700">
                    {getModeIcon(itinerary.travelMode)}
                    {itinerary.travelMode || 'Car'}
                </div>
            </div>
        </div>
      </div>

      {/* Demand Chart */}
      <div className="mb-8">
         <DemandChart stops={itinerary.stops} />
      </div>

      {/* Timeline */}
      <div className="relative pl-4 lg:pl-8 space-y-0">
        <div className="absolute left-[31px] lg:left-[47px] top-4 bottom-10 w-0.5 bg-gray-200"></div>

        {/* ORIGIN NODE */}
        {itinerary.origin && (
            <div className="relative pb-4">
                <div className="absolute left-[19px] lg:left-[35px] top-6 w-6 h-6 rounded-full border-[3px] z-10 bg-white border-green-500 shadow-sm flex items-center justify-center">
                    <div className="w-2 h-2 bg-green-500 rounded-full"></div>
                </div>
                <div className="ml-12 lg:ml-16 pt-5">
                    <div className="bg-green-50 rounded-xl p-4 border border-green-100 flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center border border-green-100 text-green-600">
                            <PlayCircle className="w-5 h-5 fill-current" />
                        </div>
                        <div>
                            <p className="text-[10px] uppercase font-bold text-green-600 tracking-wider">Starting Point</p>
                            <h3 className="text-lg font-bold text-gray-900">{itinerary.origin}</h3>
                             {itinerary.startDate && (
                                <p className="text-sm text-gray-500 font-medium flex items-center gap-1">
                                    <Calendar className="w-3 h-3" />
                                    {getExactDate(1)}
                                </p>
                             )}
                        </div>
                    </div>
                </div>
            </div>
        )}

        {itinerary.stops.map((stop, index) => {
          const isExpanded = expandedStopIndex === index;
          const exactDate = getExactDate(stop.day);
          const legIcon = getModeIcon(stop.transportMode || itinerary.travelMode);
          const isLast = index === itinerary.stops.length - 1;

          // Determine previous city for map link
          const prevCity = index === 0 ? itinerary.origin : itinerary.stops[index-1].city;

          return (
            <div key={index} className="relative pb-10 last:pb-0">
               {/* INCOMING TRAVEL CARD (Shows travel FROM prev city TO this stop) */}
               {(stop.travelTimeFromPrev) && prevCity && (
                   <div className="ml-12 lg:ml-16 mb-6">
                      <div className="flex flex-col sm:flex-row gap-3">
                        <div className="flex-1 flex items-center p-3 rounded-xl bg-white border border-gray-200 shadow-sm transition-shadow group/card relative overflow-hidden">
                          <div className="absolute left-0 top-0 bottom-0 w-1 bg-gray-900"></div>
                          <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center mr-3 text-gray-500">
                                {legIcon}
                          </div>
                          <div className="flex-1">
                              <div className="flex justify-between items-center">
                                  <div>
                                      <p className="text-[10px] uppercase tracking-wider text-gray-400 font-bold mb-0.5">
                                          Travel from {prevCity.split(',')[0]}
                                      </p>
                                      <p className="text-base font-bold text-gray-900">{stop.travelTimeFromPrev}</p>
                                  </div>
                              </div>
                          </div>
                        </div>

                         {/* MAP LINK BUTTON */}
                         <a 
                          href={getMapsTrafficLink(prevCity, stop.city)}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="sm:w-auto w-full flex items-center justify-center gap-2 px-4 py-2 rounded-xl bg-blue-50 border border-blue-100 text-blue-600 hover:bg-blue-100 hover:border-blue-200 transition-all"
                        >
                            <Map className="w-4 h-4" />
                            <span className="font-bold text-xs">Route</span>
                        </a>
                      </div>
                   </div>
               )}


              {/* Timeline Marker */}
              <div className={`absolute left-[19px] lg:left-[35px] top-6 w-6 h-6 rounded-full border-[3px] z-10 bg-white ${
                 isLast ? 'border-black' : 'border-[#FF385C]'
              } shadow-sm flex items-center justify-center`}>
                  {isLast && <div className="w-2 h-2 bg-black rounded-full"></div>}
              </div>

              <div 
                className={`ml-12 lg:ml-16 bg-white rounded-2xl p-6 border transition-all cursor-pointer group hover:shadow-lg ${isExpanded ? 'border-[#FF385C] shadow-md' : 'border-gray-200 shadow-sm'}`}
                onClick={() => toggleExpand(index)}
              >
                <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-2 flex-wrap">
                      <span className="bg-gray-100 text-gray-600 text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wide">
                        Day {stop.day}
                      </span>
                      {exactDate && (
                         <div className="flex items-center gap-1.5 text-gray-500 text-xs font-semibold">
                            <Calendar className="w-3 h-3" />
                            {exactDate}
                         </div>
                      )}
                      <div className="flex items-center gap-1.5 bg-indigo-50 text-indigo-600 px-2 py-1 rounded-full text-xs font-bold">
                        <Moon className="w-3 h-3" />
                        {stop.nightsToStay} Nights
                      </div>

                      {/* PROMINENT Target Arrival Badge */}
                      {stop.targetArrivalDate && (
                        <div className="flex items-center gap-1.5 bg-[#FF385C] text-white px-3 py-1 rounded-full text-xs font-bold shadow-sm animate-pulse">
                          <Target className="w-3 h-3" />
                          MUST ARRIVE: {stop.targetArrivalDate}
                        </div>
                      )}
                    </div>

                    <h3 className="text-xl font-extrabold text-gray-900 flex items-center gap-2 group-hover:text-[#FF385C] transition-colors">
                        {stop.city}
                        {isExpanded ? <ChevronUp className="w-4 h-4 text-gray-400" /> : <ChevronDown className="w-4 h-4 text-gray-400" />}
                    </h3>

                    <div className="flex flex-wrap items-center gap-2 text-sm text-gray-500 mt-1 font-medium">
                       <div className="flex items-center gap-1.5">
                         <TrendingUp className="w-4 h-4 text-green-500" />
                         <span>Opportunity: {stop.activity}</span>
                       </div>
                       {stop.trendVelocity && (
                         <>
                           <span className="text-gray-300 hidden sm:inline">|</span>
                           <div className="flex items-center gap-1 bg-blue-50 text-blue-700 px-2 py-0.5 rounded-full text-xs font-bold border border-blue-100">
                              <Zap className="w-3 h-3 fill-current" />
                              {stop.trendVelocity}
                           </div>
                         </>
                       )}
                    </div>
                  </div>

                  <div className="flex flex-col items-end">
                     <div className={`text-2xl font-black ${
                       stop.demandScore >= 85 ? 'text-green-500' : stop.demandScore >= 60 ? 'text-blue-500' : stop.demandScore >= 40 ? 'text-yellow-500' : 'text-gray-300'
                     }`}>{stop.demandScore}</div>
                     <span className="text-[10px] font-bold text-gray-400 uppercase">Demand Score</span>
                  </div>
                </div>

                {isExpanded && (
                    <div className="mt-6 pt-6 border-t border-gray-100 animate-in fade-in slide-in-from-top-2 duration-300">
                         <p className="text-gray-600 leading-relaxed mb-6">
                            {stop.description}
                        </p>

                        {/* Area Demand Cluster Info */}
                        {stop.clusterInfo && (
                           <div className="mb-6 bg-gradient-to-r from-gray-50 to-white p-4 rounded-xl border border-gray-100">
                               <div className="flex items-center gap-2 mb-2">
                                  <Layers className="w-4 h-4 text-[#FF385C]" />
                                  <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">ADC Context</span>
                               </div>
                               <div className="flex gap-6">
                                  <div>
                                     <p className="text-[10px] text-gray-400 font-semibold uppercase">Cluster Anchor</p>
                                     <p className="text-sm font-bold text-gray-900">{stop.clusterInfo.anchorCity}</p>
                                  </div>
                                  <div>
                                     <p className="text-[10px] text-gray-400 font-semibold uppercase">Cluster Volume</p>
                                     <p className="text-sm font-bold text-gray-900">{stop.clusterInfo.clusterVolume}</p>
                                  </div>
                                </div>
                           </div>
                        )}

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 bg-gray-50 p-4 rounded-xl">
                            <div>
                                <h4 className="text-gray-400 text-[10px] font-bold uppercase mb-3">Location</h4>
                                <div className="space-y-2">
                                    <div className="flex items-center gap-2 text-gray-700 text-sm font-medium">
                                        <MapPin className="w-4 h-4 text-gray-400" />
                                        <span>{stop.coordinates ? `${stop.coordinates.lat.toFixed(4)}, ${stop.coordinates.lng.toFixed(4)}` : 'N/A'}</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-gray-700 text-sm font-medium">
                                        <Calendar className="w-4 h-4 text-gray-400" />
                                        <span>Check-in: {exactDate || 'TBD'}</span>
                                    </div>
                                </div>
                            </div>
                             <div>
                                <h4 className="text-gray-400 text-[10px] font-bold uppercase mb-3">Logistics</h4>
                                <div className="space-y-2">
                                     <div className="flex items-center gap-2 text-gray-700 text-sm font-medium">
                                        <Moon className="w-4 h-4 text-gray-400" />
                                        <span>{stop.nightsToStay} Night{stop.nightsToStay !== 1 ? 's' : ''} stay</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-gray-700 text-sm font-medium">
                                        <span className="text-gray-400">{legIcon}</span>
                                        <span>Arriving by {stop.transportMode || itinerary.travelMode || 'Mixed'}</span>
                                    </div>
                                    {stop.trafficCondition && (
                                       <div className="flex items-center gap-2 text-orange-600 text-sm font-medium bg-orange-50 px-2 py-1 rounded">
                                          <Car className="w-4 h-4" />
                                          <span className="line-clamp-1">{stop.trafficCondition}</span>
                                       </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                )}
              </div>

              {/* Optional: Final Leg to Destination if this is the last stop and not destination */}
              {isLast && itinerary.destination && stop.travelToNext && (
                   <div className="ml-12 lg:ml-16 mt-6">
                      <div className="flex flex-col sm:flex-row gap-3">
                         <div className="flex-1 flex items-center p-3 rounded-xl bg-white border border-gray-200 shadow-sm opacity-80">
                            <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center mr-3 text-gray-400">
                                {legIcon}
                            </div>
                             <div className="flex-1">
                                <p className="text-[10px] uppercase tracking-wider text-gray-400 font-bold mb-0.5">
                                    Final Leg to {itinerary.destination}
                                </p>
                                <p className="text-base font-bold text-gray-900">{stop.travelToNext}</p>
                            </div>
                         </div>
                      </div>
                   </div>
              )}
            </div>
          );
        })}

        {/* DESTINATION NODE */}
        {itinerary.destination && (
             <div className="relative pt-6">
                 <div className="absolute left-[19px] lg:left-[35px] top-6 w-6 h-6 rounded-full border-[3px] z-10 bg-white border-black shadow-sm flex items-center justify-center">
                    <div className="w-2 h-2 bg-black rounded-full"></div>
                </div>
                 <div className="ml-12 lg:ml-16 pt-5">
                    <div className="bg-gray-100 rounded-xl p-4 border border-gray-200 flex items-center gap-3 opacity-80">
                        <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center border border-gray-200 text-black">
                            <Flag className="w-5 h-5 fill-current" />
                        </div>
                        <div>
                            <p className="text-[10px] uppercase font-bold text-gray-500 tracking-wider">Destination</p>
                            <h3 className="text-lg font-bold text-gray-900">{itinerary.destination}</h3>
                        </div>
                    </div>
                 </div>
             </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { InputForm } from './components/InputForm';
import { ItineraryDisplay } from './components/ItineraryDisplay';
import { MarketInsights } from './components/MarketInsights';
import { TripFormData, Itinerary, MarketInsight, ValidationErrors } from './types';
import { DEFAULT_FORM_DATA } from './constants';
import { generateItinerary, generateMarketInsights } from './services/geminiService';
import { MapPin, X, AlertCircle, Lightbulb, TrendingUp, Compass } from 'lucide-react';

type ViewMode = 'planner' | 'insights';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewMode>('planner');

  // Itinerary State
  const [itinerary, setItinerary] = useState<Itinerary | null>(null);
  const [isItineraryLoading, setIsItineraryLoading] = useState(false);
  const [itineraryError, setItineraryError] = useState<string | null>(null);
  const [validationErrors, setValidationErrors] = useState<ValidationErrors>({});
  const [showResultsMobile, setShowResultsMobile] = useState(false);
  const [lastSubmittedData, setLastSubmittedData] = useState<TripFormData | null>(null);

  // Insights State
  const [insights, setInsights] = useState<MarketInsight | null>(null);
  const [isInsightsLoading, setIsInsightsLoading] = useState(false);

  const handleFetchInsights = async () => {
    setIsInsightsLoading(true);
    try {
        const result = await generateMarketInsights();
        setInsights(result);
    } catch (e) {
        console.error("Failed to fetch insights");
    } finally {
        setIsInsightsLoading(false);
    }
  };

  const switchView = (view: ViewMode) => {
      setCurrentView(view);
      if (view === 'insights' && !insights && !isInsightsLoading) {
          handleFetchInsights();
      }
  };

  const handleGenerate = async (data: TripFormData, isAlternative: boolean) => {
    setIsItineraryLoading(true);
    setItineraryError(null);
    setValidationErrors({});

    // Client-side Validation using UTC-noon to be timezone-robust
    const errors: ValidationErrors = {};

    if (!data.origin || !data.origin.trim()) {
      errors.origin = { message: "Origin is required", suggestion: "Enter a starting city (e.g., 'New York, NY')" };
    }
    if (!data.destination || !data.destination.trim()) {
      errors.destination = { message: "Destination is required", suggestion: "Enter a destination city" };
    }

    if (data.startDate && data.endDate) {
      // Use YYYY-MM-DD + Midnight UTC for comparison
      const start = new Date(`${data.startDate}T00:00:00Z`);
      const end = new Date(`${data.endDate}T00:00:00Z`);
      if (start.getTime() > end.getTime()) {
         errors.startDate = { message: "Invalid date range", suggestion: "Start date must be before Return date" };
         errors.endDate = { message: "Invalid date range", suggestion: "Return date must be after Start date" };
      }
    }

    if (Object.keys(errors).length > 0) {
        setValidationErrors(errors);
        setIsItineraryLoading(false);
        return;
    }

    setLastSubmittedData(data);

    if (window.innerWidth < 1024) {
      setShowResultsMobile(true);
    }

    try {
      const result = await generateItinerary(data, isAlternative);
      setItinerary(result);
    } catch (err: any) {
      setItineraryError(err.message || "Failed to generate itinerary. Please try again.");
    } finally {
      setIsItineraryLoading(false);
    }
  };

  const getErrorDetails = (errorMessage: string) => {
    const lowerMsg = errorMessage.toLowerCase();
    if (lowerMsg.includes('api') || lowerMsg.includes('key') || lowerMsg.includes('quota') || lowerMsg.includes('network')) {
      return {
        title: "Connection or Service Issue",
        suggestions: [
          "Check your internet connection.",
          "The AI service might be experiencing high traffic.",
          "Verify your API key configuration."
        ]
      };
    }
    return {
      title: "Planning Interrupted",
      suggestions: [
        "Try increasing 'Max Drive Hours' to open up more routes.",
        "Reduce constraints or mandatory stops to simplify the request.",
        "Try generating the plan again in a few moments."
      ]
    };
  };

  return (
    <div className="flex flex-col h-screen bg-gray-50 text-[#222222] font-sans">
      <header className="flex-none bg-white border-b border-gray-200 z-50 sticky top-0 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-2 text-[#FF385C] cursor-pointer" onClick={() => setCurrentView('planner')}>
            <MapPin className="w-8 h-8 fill-current" />
            <h1 className="text-2xl font-bold tracking-tight text-[#FF385C] hidden sm:block">
              RoadTripPro
            </h1>
          </div>

          <div className="flex items-center gap-6 text-sm font-semibold text-gray-500">
            <button 
                onClick={() => switchView('planner')}
                className={`py-2 transition-colors flex items-center gap-2 ${currentView === 'planner' ? 'text-gray-900 border-b-2 border-gray-900' : 'hover:text-gray-800'}`}
            >
                <Compass className="w-4 h-4" />
                Plan a Trip
            </button>
            <button 
                onClick={() => switchView('insights')}
                className={`py-2 transition-colors flex items-center gap-2 ${currentView === 'insights' ? 'text-gray-900 border-b-2 border-gray-900' : 'hover:text-gray-800'}`}
            >
                <TrendingUp className="w-4 h-4" />
                Market Insights
            </button>
          </div>

          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-full bg-gray-100 border border-gray-200 flex items-center justify-center text-gray-500 hover:shadow-md transition-shadow cursor-pointer">
                <span className="text-xs font-bold">JD</span>
             </div>
          </div>
        </div>
      </header>

      <main className="flex-1 overflow-hidden relative">
        <div className="max-w-7xl mx-auto h-full p-0 lg:p-6">

          {currentView === 'planner' ? (
             <div className="flex flex-col lg:flex-row gap-8 h-full">
                <div className={`w-full lg:w-[400px] flex-none h-full bg-white lg:rounded-2xl lg:shadow-xl lg:border lg:border-gray-100 overflow-hidden flex flex-col z-20 transition-transform duration-300 ${showResultsMobile ? '-translate-x-full absolute' : 'translate-x-0 relative'} lg:translate-x-0 lg:relative`}>
                    <InputForm 
                      initialData={DEFAULT_FORM_DATA} 
                      onSubmit={handleGenerate}
                      isLoading={isItineraryLoading}
                      validationErrors={validationErrors}
                    />

                    {itineraryError && (
                    <div className="mx-6 mb-6 relative overflow-hidden rounded-xl bg-red-50 border border-red-100 shadow-sm animate-in fade-in slide-in-from-top-2">
                        <div className="absolute left-0 top-0 bottom-0 w-1 bg-red-500"></div>
                        <div className="p-4">
                        <div className="flex items-start gap-3">
                            <div className="flex-shrink-0 mt-0.5">
                            <AlertCircle className="w-5 h-5 text-red-600" />
                            </div>
                            <div className="flex-1">
                            <h3 className="text-sm font-bold text-red-900 mb-1">
                                {getErrorDetails(itineraryError).title}
                            </h3>
                            <p className="text-sm text-red-800 leading-relaxed font-medium mb-3">
                                {itineraryError}
                            </p>

                            <div className="bg-white/60 rounded-lg p-3 border border-red-100">
                                <div className="flex items-center gap-2 mb-2 text-red-900/70 text-xs font-bold uppercase tracking-wider">
                                <Lightbulb className="w-3 h-3" />
                                <span>Try This</span>
                                </div>
                                <ul className="space-y-1.5">
                                {getErrorDetails(itineraryError).suggestions.map((suggestion, idx) => (
                                    <li key={idx} className="text-xs text-red-700 flex items-start gap-2">
                                    <span className="mt-1.5 w-1 h-1 rounded-full bg-red-400 flex-shrink-0"></span>
                                    <span className="leading-snug">{suggestion}</span>
                                    </li>
                                ))}
                                </ul>
                            </div>
                            </div>
                            <button 
                            onClick={() => setItineraryError(null)}
                            className="flex-shrink-0 -mr-1 -mt-1 p-2 text-red-400 hover:text-red-700 hover:bg-red-100 rounded-full transition-all"
                            >
                            <X className="w-4 h-4" />
                            </button>
                        </div>
                        </div>
                    </div>
                    )}
                </div>

                <div className={`flex-1 h-full overflow-hidden bg-white lg:bg-transparent rounded-none lg:rounded-2xl relative transition-transform duration-300 ${showResultsMobile ? 'translate-x-0 absolute inset-0 z-30' : 'translate-x-full absolute'} lg:translate-x-0 lg:relative lg:inset-auto lg:z-0`}>
                    <div className="lg:hidden absolute top-4 left-4 z-50">
                        <button 
                        onClick={() => setShowResultsMobile(false)}
                        className="bg-white p-2 rounded-full shadow-lg border border-gray-100 text-gray-700 font-bold text-sm px-4"
                        >
                        ← Edit Plan
                        </button>
                    </div>

                    <ItineraryDisplay 
                      itinerary={itinerary} 
                      isLoading={isItineraryLoading} 
                      onGenerateAlternative={() => {
                        if (lastSubmittedData) {
                          handleGenerate(lastSubmittedData, true);
                        }
                      }}
                    />
                </div>
             </div>
          ) : (
             <div className="h-full bg-transparent">
                 <MarketInsights insights={insights} isLoading={isInsightsLoading} onRefresh={handleFetchInsights} />
             </div>
          )}

        </div>
      </main>
    </div>
  );
};

export default App;

