export const ItineraryDisplay: React.FC<ItineraryDisplayProps> = ({ itinerary, isLoading, onGenerateAlternative }) => {
  const [expandedStopIndex, setExpandedStopIndex] = useState<number | null>(null);

  if (isLoading) {
    return <SkeletonLoader />;
  }

  if (!itinerary) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-8 bg-gray-50/50 rounded-2xl border-2 border-dashed border-gray-200 lg:mr-6 lg:mt-6">
        <div className="bg-white p-6 rounded-full shadow-lg mb-6">
           <Map className="w-12 h-12 text-[#FF385C]" />
        </div>
        <h3 className="text-2xl font-bold text-gray-800 mb-3">Ready to Plan?</h3>
        <p className="max-w-md text-gray-500 leading-relaxed">
          Configure your trip on the left and tap <span className="font-bold text-gray-900">"Explore Plan"</span>. We'll find the most profitable stops for your journey.
        </p>
      </div>
    );
  }

  if (itinerary.stops.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center p-8 bg-gray-50/50 rounded-2xl border-2 border-dashed border-gray-200 lg:mr-6 lg:mt-6">
        <div className="bg-white p-6 rounded-full shadow-lg mb-6">
           <AlertTriangle className="w-12 h-12 text-yellow-500" />
        </div>
        <h3 className="text-2xl font-bold text-gray-800 mb-3">No Viable Stops Found</h3>
        <p className="max-w-md text-gray-500 leading-relaxed mb-6">
          We analyzed the route but couldn't identify stops that meet your profitability criteria or constraints.
        </p>
        <div className="bg-white border border-gray-200 rounded-xl p-6 max-w-lg w-full shadow-sm text-left">
           <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">AI Analysis</h4>
           <p className="text-sm text-gray-700 leading-relaxed">
             {itinerary.summary || "Try adjusting your travel dates, increasing max drive hours, or changing your route to find better opportunities."}
           </p>
        </div>
      </div>
    );
  }

  const toggleExpand = (index: number) => {
    setExpandedStopIndex(expandedStopIndex === index ? null : index);
  };

  /**
   * Robust Date Calculation handling UTC to avoid timezone shifts.
   * Handles leap years and date rollovers automatically by using UTC midnights.
   */
  const getExactDate = (dayOffset: number): string | null => {
    if (!itinerary.startDate) return null;

    // Parse YYYY-MM-DD Safely
    const parts = itinerary.startDate.split('-').map(Number);
    if (parts.length !== 3 || parts.some(isNaN)) return null;
    const [year, month, day] = parts;

    // Use UTC Midnight as anchor. setUTCDate correctly rolls month/year.
    const date = new Date(Date.UTC(year, month - 1, day, 12, 0, 0)); // Noon buffer
    date.setUTCDate(date.getUTCDate() + Math.floor(dayOffset - 1));

    return date.toLocaleDateString('en-US', { 
      weekday: 'short', 
      month: 'short', 
      day: 'numeric',
      year: 'numeric',
      timeZone: 'UTC'
    });
  };

  const getModeIcon = (mode: string | undefined) => {
    const normalizeMode = mode?.toLowerCase() || '';
    if (normalizeMode.includes('car')) return <Car className="w-5 h-5" />;
    if (normalizeMode.includes('bus')) return <Bus className="w-5 h-5" />;
    if (normalizeMode.includes('plane') || normalizeMode.includes('flight')) return <Plane className="w-5 h-5" />;
    if (normalizeMode.includes('mixed')) return <Shuffle className="w-5 h-5" />;
    return <Navigation className="w-5 h-5" />;
  };

  const getMapsTrafficLink = (originCity: string, destinationCity: string) => {
    const origin = encodeURIComponent(originCity);
    const dest = encodeURIComponent(destinationCity);
    return `https://www.google.com/maps/dir/?api=1&origin=${origin}&destination=${dest}&travelmode=driving&layer=t`;
  };

  return (
    <div className="h-full overflow-y-auto px-4 pb-12 lg:pr-6 custom-scrollbar">
      {/* Hero Header */}
      <div className="bg-white rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.06)] border border-gray-100 overflow-hidden mb-8 mt-2 lg:mt-6">
        <div className="bg-gradient-to-r from-[#FF385C] to-[#E00B41] h-32 relative">
             <div className="absolute -bottom-10 right-8 bg-white p-4 rounded-2xl shadow-lg border border-gray-100 flex items-center gap-4">
                <div className="text-center pr-4 border-r border-gray-100">
                    <p className="text-[10px] uppercase font-bold text-gray-400">Total Profitability</p>
                    <div className="flex items-center gap-1 justify-center">
                        <Star className="w-5 h-5 text-yellow-400 fill-yellow-400" />
                        <span className="text-2xl font-black text-gray-900">High</span>
                    </div>
                </div>
                {onGenerateAlternative && (
                  <button 
                    onClick={onGenerateAlternative}
                    className="flex flex-col items-center group transition-colors"
                  >
                    <div className="p-2 rounded-full bg-gray-50 group-hover:bg-gray-100 text-gray-400 group-hover:text-[#FF385C] transition-all">
                      <Shuffle className="w-6 h-6" />
                    </div>
                    <span className="text-[10px] font-bold text-gray-500 group-hover:text-gray-900 uppercase tracking-tighter mt-1">Alternative</span>
                  </button>
                )}
             </div>
        </div>
        <div className="px-8 pt-6 pb-8">
            <h2 className="text-3xl font-extrabold text-gray-900 mb-2">{itinerary.routeName}</h2>
            <p className="text-gray-500 text-lg leading-relaxed mb-6 max-w-2xl">{itinerary.summary}</p>

            <div className="flex flex-wrap gap-3">
                <div className="px-4 py-2 bg-gray-50 rounded-full border border-gray-200 flex items-center gap-2 text-sm font-semibold text-gray-700">
                    <Navigation className="w-4 h-4 text-[#FF385C]" />
                    {itinerary.totalDistance}
                </div>
                 <div className="px-4 py-2 bg-gray-50 rounded-full border border-gray-200 flex items-center gap-2 text-sm font-semibold text-gray-700">
                    <Clock className="w-4 h-4 text-[#FF385C]" />
                    {itinerary.totalDuration}
                </div>
                 <div className="px-4 py-2 bg-gray-50 rounded-full border border-gray-200 flex items-center gap-2 text-sm font-semibold text-gray-700">
                    {getModeIcon(itinerary.travelMode)}
                    {itinerary.travelMode || 'Car'}
                </div>
                {onGenerateAlternative && (
                   <button 
                    onClick={onGenerateAlternative}
                    className="px-4 py-2 bg-white rounded-full border border-gray-200 hover:border-[#FF385C] flex items-center gap-2 text-sm font-bold text-gray-600 hover:text-[#FF385C] transition-all"
                  >
                      <RefreshCw className="w-4 h-4" />
                      Generate Alternative
                  </button>
                )}
            </div>
        </div>
      </div>

      {/* Demand Chart */}
      <div className="mb-8">
         <DemandChart stops={itinerary.stops} />
      </div>

      {/* Timeline */}
      <div className="relative pl-4 lg:pl-8 space-y-0">
        <div className="absolute left-[31px] lg:left-[47px] top-4 bottom-10 w-0.5 bg-gray-200"></div>

        {/* ORIGIN NODE */}
        {itinerary.origin && (
            <div className="relative pb-4">
                <div className="absolute left-[19px] lg:left-[35px] top-6 w-6 h-6 rounded-full border-[3px] z-10 bg-white border-green-500 shadow-sm flex items-center justify-center">
                    <div className="w-2 h-2 bg-green-500 rounded-full"></div>
                </div>
                <div className="ml-12 lg:ml-16 pt-5">
                    <div className="bg-green-50 rounded-xl p-4 border border-green-100 flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center border border-green-100 text-green-600">
                            <PlayCircle className="w-5 h-5 fill-current" />
                        </div>
                        <div>
                            <p className="text-[10px] uppercase font-bold text-green-600 tracking-wider">Starting Point</p>
                            <h3 className="text-lg font-bold text-gray-900">{itinerary.origin}</h3>
                             {itinerary.startDate && (
                                <p className="text-sm text-gray-500 font-medium flex items-center gap-1">
                                    <Calendar className="w-3 h-3" />
                                    {getExactDate(1)}
                                </p>
                             )}
                        </div>
                    </div>
                </div>
            </div>
        )}

        {itinerary.stops.map((stop, index) => {
          const isExpanded = expandedStopIndex === index;
          const exactDate = getExactDate(stop.day);
          const legIcon = getModeIcon(stop.transportMode || itinerary.travelMode);
          const isLast = index === itinerary.stops.length - 1;

          // Determine previous city for map link
          const prevCity = index === 0 ? itinerary.origin : itinerary.stops[index-1].city;

          return (
            <div key={index} className="relative pb-10 last:pb-0">
               {/* INCOMING TRAVEL CARD */}
               {(stop.travelTimeFromPrev) && prevCity && (
                   <div className="ml-12 lg:ml-16 mb-6">
                      <div className="flex flex-col sm:flex-row gap-3">
                        <div className="flex-1 flex items-center p-3 rounded-xl bg-white border border-gray-200 shadow-sm transition-shadow group/card relative overflow-hidden">
                          <div className="absolute left-0 top-0 bottom-0 w-1 bg-gray-900"></div>
                          <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center mr-3 text-gray-500">
                                {legIcon}
                          </div>
                          <div className="flex-1">
                              <div className="flex justify-between items-center">
                                  <div>
                                      <p className="text-[10px] uppercase tracking-wider text-gray-400 font-bold mb-0.5">
                                          Travel from {prevCity.split(',')[0]}
