                        {stop.clusterInfo && (
                           <div className="mb-6 bg-gradient-to-r from-gray-50 to-white p-4 rounded-xl border border-gray-100">
                               <div className="flex items-center gap-2 mb-2">
                                  <Layers className="w-4 h-4 text-[#FF385C]" />
                                  <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">ADC Context</span>
                               </div>
                               <div className="flex gap-6">
                                  <div>
                                     <p className="text-[10px] text-gray-400 font-semibold uppercase">Cluster Anchor</p>
                                     <p className="text-sm font-bold text-gray-900">{stop.clusterInfo.anchorCity}</p>
                                  </div>
                                  <div>
                                     <p className="text-[10px] text-gray-400 font-semibold uppercase">Cluster Volume</p>
                                     <p className="text-sm font-bold text-gray-900">{stop.clusterInfo.clusterVolume}</p>
                                  </div>
                                </div>
                           </div>
                        )}

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 bg-gray-50 p-4 rounded-xl">
                            <div>
                                <h4 className="text-gray-400 text-[10px] font-bold uppercase mb-3">Location</h4>
                                <div className="space-y-2">
                                    <div className="flex items-center gap-2 text-gray-700 text-sm font-medium">
                                        <MapPin className="w-4 h-4 text-gray-400" />
                                        <span>{stop.coordinates ? `${stop.coordinates.lat.toFixed(4)}, ${stop.coordinates.lng.toFixed(4)}` : 'N/A'}</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-gray-700 text-sm font-medium">
                                        <Calendar className="w-4 h-4 text-gray-400" />
                                        <span>Check-in: {exactDate || 'TBD'}</span>
                                    </div>
                                </div>
                            </div>
                             <div>
                                <h4 className="text-gray-400 text-[10px] font-bold uppercase mb-3">Logistics</h4>
                                <div className="space-y-2">
                                     <div className="flex items-center gap-2 text-gray-700 text-sm font-medium">
                                        <Moon className="w-4 h-4 text-gray-400" />
                                        <span>{stop.nightsToStay} Night{stop.nightsToStay !== 1 ? 's' : ''} stay</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-gray-700 text-sm font-medium">
                                        <span className="text-gray-400">{legIcon}</span>
                                        <span>Arriving by {stop.transportMode || itinerary.travelMode || 'Mixed'}</span>
                                    </div>
                                    {stop.trafficCondition && (
                                       <div className="flex items-center gap-2 text-orange-600 text-sm font-medium bg-orange-50 px-2 py-1 rounded">
                                          <Car className="w-4 h-4" />
                                          <span className="line-clamp-1">{stop.trafficCondition}</span>
                                       </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                )}
              </div>

              {isLast && itinerary.destination && stop.travelToNext && (
                   <div className="ml-12 lg:ml-16 mt-6">
                      <div className="flex flex-col sm:flex-row gap-3">
                         <div className="flex-1 flex items-center p-3 rounded-xl bg-white border border-gray-200 shadow-sm opacity-80">
                            <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center mr-3 text-gray-400">
                                {legIcon}
                            </div>
                             <div className="flex-1">
                                <p className="text-[10px] uppercase tracking-wider text-gray-400 font-bold mb-0.5">
                                    Final Leg to {itinerary.destination}
                                </p>
                                <p className="text-base font-bold text-gray-900">{stop.travelToNext}</p>
                            </div>
                         </div>
                      </div>
                   </div>
              )}
            </div>
          );
        })}

        {/* DESTINATION NODE */}
        {itinerary.destination && (
             <div className="relative pt-6">
                 <div className="absolute left-[19px] lg:left-[35px] top-6 w-6 h-6 rounded-full border-[3px] z-10 bg-white border-black shadow-sm flex items-center justify-center">
                    <div className="w-2 h-2 bg-black rounded-full"></div>
                </div>
                 <div className="ml-12 lg:ml-16 pt-5">
                    <div className="bg-gray-100 rounded-xl p-4 border border-gray-200 flex items-center gap-3 opacity-80">
                        <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center border border-gray-200 text-black">
                            <Flag className="w-5 h-5 fill-current" />
                        </div>
                        <div>
                            <p className="text-[10px] uppercase font-bold text-gray-500 tracking-wider">Destination</p>
                            <h3 className="text-lg font-bold text-gray-900">{itinerary.destination}</h3>
                        </div>
                    </div>
                 </div>
             </div>
        )}
      </div>
    </div>
  );
};

