export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();

  const mandatoryStopsText = data.mandatoryStops
    .map(s => {
      let info = s.location;
      const dateVal = s.arrivalDate || s.date;
      if (dateVal) info += ` (Must arrive on: ${dateVal})`;
      if (s.nights) info += ` (Stay: ${s.nights} nights)`;
      return info;
    })
    .join(', ');

  const destinationText = data.destinationDate 
    ? `${data.destination} (Target Arrival: ${data.destinationDate})` 
    : data.destination;

  let modeText: string = data.travelMode;
  if (data.travelMode === TravelMode.Mixed && data.travelModeDetail) {
    modeText = `${TravelMode.Mixed}: ${data.travelModeDetail}`;
  }

  const prompt = `
    Act as a high-precision algorithmic engine for a professional Male Massage Therapist.
    Plan a profitable road trip from ${data.origin} to ${destinationText}.

    Context:
    - Mode: ${modeText}
    - Max Drive: ${data.maxDriveHours}h/day.
    - Dates: ${data.startDate || 'TBD'} to ${data.endDate || 'TBD'}.
    - Mandatory Stops: ${mandatoryStopsText}.

    ${KEYWORD_MARKET_DATA}

    YOU MUST EXECUTE THE FOLLOWING ALGORITHM:
    1. Use Google Search Grounding to verify actual search demand and events for specific cities.
    2. Sequence stops logically within the max drive time.
    3. Return only valid JSON.

    ${isAlternative ? 'Focus on high-scoring clusters that are slightly off the main highway (secondary routes).' : 'Focus on the most direct high-scoring clusters.'}
  `;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 4000 },
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
        tools: [{ googleSearch: {} }], 
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const result = JSON.parse(extractJson(text)) as Itinerary;

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
        const sources: GroundingSource[] = [];
        chunks.forEach((chunk: any) => {
            if (chunk.web) {
                sources.push({
                    title: chunk.web.title || "Search Result",
                    uri: chunk.web.uri
                });
            }
        });
        result.sources = Array.from(new Map(sources.map(s => [s.uri, s])).values());
    }

    if (result.stops && data.mandatoryStops.length > 0) {
      const parseDateToUTC = (dateStr: string) => {
         const [y, m, d] = dateStr.split('-').map(Number);
         return Date.UTC(y, m - 1, d);
      };

      const tripStartMs = data.startDate ? parseDateToUTC(data.startDate) : 0;

      result.stops = result.stops.map(stop => {
        const match = data.mandatoryStops.find(ms => 
          stop.city.toLowerCase().includes(ms.location.toLowerCase()) || 
          ms.location.toLowerCase().includes(stop.city.toLowerCase())
        );

        if (match) {
          const userDate = match.arrivalDate || match.date;
          if (userDate) {
            const updatedStop = { ...stop, targetArrivalDate: userDate };
            if (tripStartMs > 0) {
                 const targetMs = parseDateToUTC(userDate);
                 const msPerDay = 1000 * 60 * 60 * 24;
                 const diffDays = Math.round((targetMs - tripStartMs) / msPerDay);
                 if (diffDays >= 0) updatedStop.day = diffDays + 1;
            }
            return updatedStop;
          }
        }
        return stop;
      });
      result.stops.sort((a, b) => a.day - b.day);
    }

    if (data.startDate) result.startDate = data.startDate;
    result.travelMode = data.travelMode;
    result.origin = data.origin;
    result.destination = data.destination;

    return result;
  } catch (error) {
    console.error("Error generating itinerary:", error);
    throw error;
  }
};

