    .map(s => `${s.location}${s.arrivalDate ? ` (Must arrive: ${s.arrivalDate})` : ''}${s.nights ? ` (Stay: ${s.nights} nights)` : ''}`)
    .join(', ');

  const destinationText = data.destinationDate 
    ? `${data.destination} (Target: ${data.destinationDate})` 
    : data.destination;

  let modeText: string = data.travelMode;
  if (data.travelMode === TravelMode.Mixed && data.travelModeDetail) {
    modeText = `${TravelMode.Mixed}: ${data.travelModeDetail}`;
  }

  const prompt = `
    Role: Professional Route Logistics Engine for a Male Massage Therapist.
    Goal: Generate a LOGICAL and PROFITABLE multi-city journey from ${data.origin} to ${destinationText}.

    Constraint Checklist:
    1. MAX DRIVE TIME: ${data.maxDriveHours} hours between any two points.
    2. MODE: ${modeText}.
    3. MANDATORY STOPS: ${mandatoryStopsText || 'None'}. Ensure these are sequenced logically based on geography.
    4. DATES: ${data.startDate || 'Flexible'} to ${data.endDate || 'Flexible'}.
    5. TARGET STOPS: ${data.numberOfStops} stops (approx).

    ${KEYWORD_MARKET_DATA}

    Routing Strategy:
    - Use Google Search to find current events, festivals, or high-growth demand in the "male wellness/massage" niche for intermediate cities.
    - PRIORITIZE: Cities with high search volume for keywords like "gay massage" or "male massage therapist".
    - ${isAlternative ? 'ALTERNATIVE ROUTE: Avoid major interstates/hubs where possible. Focus on secondary high-growth markets (emerging cities with less competition but high demand).' : 'PRIMARY ROUTE: Focus on major corridors and established high-volume hubs.'}

    Output Requirements:
    - Sequence stops GEOGRAPHICALLY from origin to destination.
    - Ensure travelTimeFromPrev does not exceed ${data.maxDriveHours} hours per leg.
    - Justify each stop's profitability in the description.
    - Return valid JSON matching the schema.
  `;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 4000 },
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
        tools: [{ googleSearch: {} }], 
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const result = JSON.parse(extractJson(text)) as Itinerary;

    // Grounding Sources
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
        const sources: GroundingSource[] = [];
        chunks.forEach((chunk: any) => {
            if (chunk.web) {
                sources.push({
                    title: chunk.web.title || "Search Result",
                    uri: chunk.web.uri
                });
            }
        });
        result.sources = Array.from(new Map(sources.map(s => [s.uri, s])).values());
    }

    // Post-processing for mandatory stop dates and sorting
    if (result.stops) {
      if (data.startDate) result.startDate = data.startDate;
      result.travelMode = data.travelMode;
      result.origin = data.origin;
      result.destination = data.destination;

      // Ensure logic sequence
      result.stops.sort((a, b) => a.day - b.day);
    }

    return result;
  } catch (error) {
    console.error("Error generating itinerary:", error);
    throw error;
  }
};

