  if (!apiKey) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

const KEYWORD_MARKET_DATA = `
MARKET DEMAND CONTEXT (Baseline Niche Data):
1. gay massage - High Interest
2. sensual massage - High Interest
3. male massage therapist - Moderate Interest
4. LGBTQ friendly massage - Moderate Interest
`;

const extractJson = (text: string) => {
  try {
    const jsonMatch = text.match(/\{[\s\S]*\}|\[[\s\S]*\]/);
    if (!jsonMatch) return null;
    return JSON.parse(jsonMatch[0]);
  } catch (e) {
    console.error("JSON Extraction failed", e);
    return null;
  }
};

export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();
  const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

  const mandatoryStopsText = data.mandatoryStops
    .map(s => `${s.location}${s.arrivalDate ? ` (Arrive: ${s.arrivalDate})` : ''}`)
    .join(', ');

  const prompt = `
    TODAY'S DATE: ${today}
    ROLE: You are a professional Logistics Analyst for the high-end male wellness sector.

    GOAL: Plan a journey from ${data.origin} to ${data.destination}${data.destinationDate ? ` (by ${data.destinationDate})` : ''}.

    CONSTRAINTS:
    - Driving Limit: ${data.maxDriveHours} hours per leg.
    - Mandatory Cities: ${mandatoryStopsText || 'None'}.
    - Stop Count: ~${data.numberOfStops} intermediate stops.
    - Strategy: ${isAlternative ? 'Alternative secondary markets.' : 'Primary hub-to-hub efficiency.'}

    ${KEYWORD_MARKET_DATA}

    DATA REQUIREMENTS:
    1. Use GOOGLE SEARCH to identify specific events (Pride festivals, circuit parties, wellness conventions, sports tournaments) happening in the next 90 days.
    2. Cross-reference potential stops with actual search demand data for "gay massage" and "male wellness" in those locations.
    3. Calculate a "Demand Score" (0-100) based on real-time factors found.
    4. Group stops into Area Demand Clusters (ADC).

    OUTPUT FORMAT (JSON):
    {
      "routeName": "name",
      "totalDistance": "distance",
      "totalDuration": "duration",
      "summary": "Explain how search data validates this route as high-revenue.",
      "stops": [
        {
          "day": number,
          "city": "string",
          "activity": "Marketing action",
          "profitabilityJustification": "Specific search findings (events, volume trends)",
          "demandScore": 0-100,
          "trendVelocity": "🔥/📈/➡️/📉",
          "clusterInfo": { "anchorCity": "string", "clusterVolume": "string" },
          "nightsToStay": number,
          "travelTimeFromPrev": "time",
          "travelToNext": "time",
          "coordinates": { "lat": number, "lng": number }
        }
      ]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 8000 },
        tools: [{ googleSearch: {} }], 
      },
    });

    const result = extractJson(response.text) as Itinerary | null;
    if (!result) throw new Error("The AI response was invalid. Please try a simpler route or different drive limit.");

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const globalSources: GroundingSource[] = [];
    if (chunks) {
        chunks.forEach((chunk: any) => {
            if (chunk.web) {
                globalSources.push({
                    title: chunk.web.title || "Reference Source",
                    uri: chunk.web.uri
                });
            }
        });
    }
    result.sources = Array.from(new Map(globalSources.map(s => [s.uri, s])).values());

    // Map global sources to stops based on keyword presence in source title
    result.stops = result.stops.map(stop => {
        const cityPrefix = stop.city.split(',')[0].toLowerCase();
        const stopSources = globalSources.filter(s => 
            s.title.toLowerCase().includes(cityPrefix) || 
            s.uri.toLowerCase().includes(cityPrefix.replace(' ', ''))
        );
        return {
            ...stop,
            stopSources: stopSources.length > 0 ? Array.from(new Map(stopSources.map(s => [s.uri, s])).values()) : undefined
        };
    });

    result.startDate = data.startDate;
    result.origin = data.origin;
    result.destination = data.destination;
    result.stops.sort((a, b) => a.day - b.day);

    return result;
  } catch (error: any) {
    console.error("Gemini Error:", error);
    throw new Error(error.message || "Route calculation failed. Check your API key and network.");
  }
};

