src/components/ItineraryDisplay.tsx
TypeScript

import React, { useState } from 'react';
import { Itinerary, DayPlan, Activity } from '../types';
import { 
  Calendar, 
  Map as MapIcon, 
  Clock, 
  Navigation, 
  Utensils, 
  Camera, 
  Car, 
  Moon, 
  RefreshCw, 
  Share2, 
  ChevronDown, 
  ChevronUp 
} from 'lucide-react';

interface ItineraryDisplayProps {
  itinerary: Itinerary | null;
  isLoading: boolean;
  onGenerateAlternative: () => void;
}

export const ItineraryDisplay: React.FC<ItineraryDisplayProps> = ({ 
  itinerary, 
  isLoading, 
  onGenerateAlternative 
}) => {
  const [activeTab, setActiveTab] = useState<'timeline' | 'map'>('timeline');

  // 1. Loading State (Skeleton UI)
  if (isLoading) {
    return (
      <div className="h-full flex flex-col bg-white lg:rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        {/* Skeleton Header */}
        <div className="p-6 border-b border-gray-100 space-y-4">
          <div className="h-8 bg-gray-100 rounded-md w-3/4 animate-pulse" />
          <div className="flex gap-3">
            <div className="h-4 bg-gray-100 rounded w-20 animate-pulse" />
            <div className="h-4 bg-gray-100 rounded w-20 animate-pulse" />
          </div>
        </div>
        {/* Skeleton Content */}
        <div className="flex-1 p-6 space-y-8 overflow-y-auto">
          {[1, 2, 3].map((i) => (
            <div key={i} className="flex gap-4">
              <div className="flex flex-col items-center gap-2">
                <div className="w-8 h-8 rounded-full bg-gray-100 animate-pulse" />
                <div className="w-0.5 h-24 bg-gray-50" />
              </div>
              <div className="flex-1 space-y-3">
                <div className="h-6 bg-gray-100 rounded w-1/3 animate-pulse" />
                <div className="h-24 bg-gray-50 rounded-xl w-full animate-pulse" />
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  // 2. Empty State
  if (!itinerary) {
    return (
      <div className="h-full flex flex-col items-center justify-center bg-white/50 lg:bg-white lg:rounded-2xl lg:border border-gray-100 text-center p-8">
        <div className="w-24 h-24 bg-rose-50 rounded-full flex items-center justify-center mb-6">
          <MapIcon className="w-10 h-10 text-[#FF385C]" />
        </div>
        <h2 className="text-2xl font-bold text-gray-900 mb-2">Ready to hit the road?</h2>
        <p className="text-gray-500 max-w-md leading-relaxed">
          Enter your trip details on the left to generate a perfectly curated day-by-day itinerary tailored to your preferences.
        </p>
      </div>
    );
  }

  // 3. Render Result
  return (
    <div className="h-full flex flex-col bg-white lg:rounded-2xl shadow-xl border border-gray-100 overflow-hidden">

      {/* Header Section */}
      <div className="flex-none p-6 border-b border-gray-100 bg-white z-10">
        <div className="flex flex-col xl:flex-row xl:items-start xl:justify-between gap-4">
          <div>
            <h2 className="text-2xl font-bold text-gray-900 leading-tight">
              {itinerary.tripTitle || "Your Road Trip Adventure"}
            </h2>
            <p className="text-gray-500 mt-1 flex items-center gap-2 text-sm">
              <Calendar className="w-4 h-4" />
              {itinerary.summary || "Custom curated itinerary"}
            </p>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={onGenerateAlternative}
              className="px-4 py-2 bg-white border border-gray-200 hover:bg-gray-50 text-gray-700 rounded-full text-sm font-medium transition-colors flex items-center gap-2 shadow-sm"
            >
              <RefreshCw className="w-4 h-4" />
              Alternative Route
            </button>
            <button className="p-2 hover:bg-gray-100 rounded-full text-gray-500 transition-colors">
              <Share2 className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* View Tabs (Optional - good for future map integration) */}
        <div className="flex gap-6 mt-6 border-b border-gray-100 -mb-6">
          <button 
            onClick={() => setActiveTab('timeline')}
            className={`pb-3 text-sm font-semibold border-b-2 transition-colors ${activeTab === 'timeline' ? 'border-[#FF385C] text-[#FF385C]' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
          >
            Timeline
          </button>
          <button 
            onClick={() => setActiveTab('map')}
            className={`pb-3 text-sm font-semibold border-b-2 transition-colors ${activeTab === 'map' ? 'border-[#FF385C] text-[#FF385C]' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
          >
            Map View
          </button>
        </div>
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-y-auto bg-gray-50/50 p-4 lg:p-6 scroll-smooth">

        {activeTab === 'map' ? (
          <div className="h-full flex items-center justify-center text-gray-400 bg-gray-100 rounded-xl border border-dashed border-gray-300">
             <div className="text-center">
                <MapIcon className="w-12 h-12 mx-auto mb-2 opacity-20" />
                <p>Map visualization coming soon</p>
             </div>
          </div>
        ) : (
          <div className="max-w-3xl mx-auto space-y-8 pb-12">
            {itinerary.days.map((day, index) => (
              <DayCard key={index} day={day} index={index} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

// --- Sub-Components ---

const DayCard: React.FC<{ day: DayPlan; index: number }> = ({ day, index }) => {
  const [isExpanded, setIsExpanded] = useState(true);

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden transition-all hover:shadow-md">
      {/* Day Header */}
      <div 
        onClick={() => setIsExpanded(!isExpanded)}
        className="p-4 flex items-center justify-between cursor-pointer bg-gray-50/50 hover:bg-gray-50 transition-colors"
      >
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-lg bg-[#FF385C]/10 flex items-center justify-center text-[#FF385C] font-bold text-lg">
            {index + 1}
          </div>
          <div>
            <h3 className="font-bold text-gray-900">Day {index + 1}</h3>
            <p className="text-sm text-gray-500 font-medium">{day.title}</p>
          </div>
        </div>
        {isExpanded ? <ChevronUp className="w-5 h-5 text-gray-400" /> : <ChevronDown className="w-5 h-5 text-gray-400" />}
      </div>

      {/* Activities Timeline */}
      {isExpanded && (
        <div className="p-4 pl-6 lg:pl-10 relative">
          {/* Vertical Line */}
          <div className="absolute left-9 lg:left-[52px] top-6 bottom-6 w-0.5 bg-gray-100" />

          <div className="space-y-6 relative">
            {day.activities.map((activity, actIndex) => (
              <ActivityItem key={actIndex} activity={activity} />
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

const ActivityItem: React.FC<{ activity: Activity }> = ({ activity }) => {
  const getIcon = (type?: string) => {
    switch (type?.toLowerCase()) {
      case 'food': return <Utensils className="w-4 h-4" />;
      case 'sightseeing': return <Camera className="w-4 h-4" />;
      case 'drive': return <Car className="w-4 h-4" />;
      case 'rest': return <Moon className="w-4 h-4" />;
      default: return <Navigation className="w-4 h-4" />;
    }
  };

  const getColor = (type?: string) => {
    switch (type?.toLowerCase()) {
      case 'food': return 'bg-orange-100 text-orange-600';
      case 'sightseeing': return 'bg-blue-100 text-blue-600';
      case 'drive': return 'bg-gray-100 text-gray-600';
      default: return 'bg-rose-100 text-rose-600';
    }
  };

  return (
    <div className="flex gap-4 relative group">
      {/* Timeline Dot */}
      <div className={`w-8 h-8 rounded-full flex-none flex items-center justify-center z-10 ring-4 ring-white ${getColor(activity.type)}`}>
        {getIcon(activity.type)}
      </div>

      {/* Content */}
      <div className="flex-1 pt-1">
        <div className="flex flex-col sm:flex-row sm:items-baseline gap-1 sm:gap-3 mb-1">
          <span className="text-xs font-bold text-gray-400 tracking-wide uppercase flex items-center gap-1">
            <Clock className="w-3 h-3" />
            {activity.time}
          </span>
          <h4 className="font-semibold text-gray-900 text-sm">
            {activity.location || "En Route"}
          </h4>
        </div>
        <p className="text-gray-600 text-sm leading-relaxed">
          {activity.description}
        </p>
      </div>
    </div>
  );
};

Key Features of this Component:

    Polished UI: Uses a "Day Card" approach. Each day is a card that can be collapsed or expanded, which helps when viewing long trips (e.g., 7+ days).

    Visual Timeline: A vertical line connects activities, with specific icons (Fork for food, Camera for sightseeing) to make the itinerary scannable at a glance.

    Adaptive Empty/Loading States:

        Loading: Uses a "Skeleton" loader (pulsing gray blocks) rather than a simple spinner. This mimics the final layout and reduces perceived wait time.

        Empty: A friendly prompt encouraging the user to start.

    Responsive: It handles padding and layout changes for mobile vs. desktop automatically via Tailwind classes.

