import React, { useState, useMemo } from 'react';
import { Itinerary, Stop } from '../types';
import { 
  Calendar, 
  Map as MapIcon, 
  Clock, 
  Navigation, 
  Utensils, 
  Camera, 
  Car, 
  Moon, 
  RefreshCw, 
  Share2, 
  ChevronDown, 
  ChevronUp,
  TrendingUp,
  AlertTriangle
} from 'lucide-react';

interface ItineraryDisplayProps {
  itinerary: Itinerary | null;
  isLoading: boolean;
  onGenerateAlternative: () => void;
}

// -- View Models --
interface Activity {
  time: string;
  location: string;
  description: string;
  type: 'food' | 'sightseeing' | 'drive' | 'rest' | 'other';
  meta?: {
    demandScore?: number;
    justification?: string;
  };
}

interface DayPlan {
  title: string;
  activities: Activity[];
}

export const ItineraryDisplay: React.FC<ItineraryDisplayProps> = ({ 
  itinerary, 
  isLoading, 
  onGenerateAlternative 
}) => {
  const [activeTab, setActiveTab] = useState<'timeline' | 'map'>('timeline');

  // --- Transform Data to View Model ---
  const dayPlans = useMemo<DayPlan[]>(() => {
    if (!itinerary?.stops) return [];

    // Group stops by day, but handle travel segments logic
    const plans: DayPlan[] = [];
    const groupedStops = new Map<number, Stop>();

    // Sort just in case
    const sortedStops = [...itinerary.stops].sort((a, b) => a.day - b.day);

    sortedStops.forEach(stop => {
        // Find or create day plan
        let dayPlan = plans.find(p => p.title.includes(`Day ${stop.day}`));

        if (!dayPlan) {
            // New Day
            dayPlan = {
                title: `${stop.city}`,
                activities: []
            };
            plans.push(dayPlan);
        }

        // 1. Add Drive Segment if applicable
        if (stop.travelTimeFromPrev) {
             dayPlan.activities.push({
                time: "Morning", // Approximate
                location: "En Route",
                description: `Drive from previous location. Duration: ${stop.travelTimeFromPrev}`,
                type: 'drive'
             });
        }

        // 2. Add Main Activity (Market Focus)
        dayPlan.activities.push({
            time: "Afternoon", 
            location: stop.city,
            description: stop.activity,
            type: 'sightseeing',
            meta: {
                demandScore: stop.demandScore,
                justification: stop.profitabilityJustification
            }
        });

        // 3. Add Stay
        if (stop.nightsToStay > 0) {
             dayPlan.activities.push({
                time: "Evening",
                location: stop.city,
                description: `Check-in for ${stop.nightsToStay} night${stop.nightsToStay > 1 ? 's' : ''}.`,
                type: 'rest'
             });
        } else {
             dayPlan.activities.push({
                time: "Evening",
                location: stop.city,
                description: "Short stopover. Continuing journey.",
                type: 'other'
             });
        }
    });

    return plans;
  }, [itinerary]);

  // 1. Loading State (Skeleton UI)
  if (isLoading) {
    return (
      <div className="h-full flex flex-col bg-white lg:rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        {/* Skeleton Header */}
        <div className="p-6 border-b border-gray-100 space-y-4">
          <div className="h-8 bg-gray-100 rounded-md w-3/4 animate-pulse" />
          <div className="flex gap-3">
            <div className="h-4 bg-gray-100 rounded w-20 animate-pulse" />
            <div className="h-4 bg-gray-100 rounded w-20 animate-pulse" />
          </div>
        </div>
        {/* Skeleton Content */}
        <div className="flex-1 p-6 space-y-8 overflow-y-auto custom-scrollbar">
          {[1, 2, 3].map((i) => (
            <div key={i} className="flex gap-4">
              <div className="flex flex-col items-center gap-2">
                <div className="w-8 h-8 rounded-full bg-gray-100 animate-pulse" />
                <div className="w-0.5 h-24 bg-gray-50" />
              </div>
              <div className="flex-1 space-y-3">
                <div className="h-6 bg-gray-100 rounded w-1/3 animate-pulse" />
                <div className="h-24 bg-gray-50 rounded-xl w-full animate-pulse" />
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  // 2. Empty State
  if (!itinerary) {
    return (
      <div className="h-full flex flex-col items-center justify-center bg-white/50 lg:bg-white lg:rounded-2xl lg:border border-gray-100 text-center p-8">
        <div className="w-24 h-24 bg-rose-50 rounded-full flex items-center justify-center mb-6 shadow-sm">
          <MapIcon className="w-10 h-10 text-[#FF385C]" />
        </div>
        <h2 className="text-2xl font-bold text-gray-900 mb-2">Ready to hit the road?</h2>
        <p className="text-gray-500 max-w-md leading-relaxed">
          Enter your trip details on the left to generate a perfectly curated day-by-day itinerary tailored to your preferences.
        </p>
      </div>
    );
  }

  // 3. Render Result
  return (
    <div className="h-full flex flex-col bg-white lg:rounded-2xl shadow-xl border border-gray-100 overflow-hidden">

      {/* Header Section */}
      <div className="flex-none p-6 border-b border-gray-100 bg-white z-10">
        <div className="flex flex-col xl:flex-row xl:items-start xl:justify-between gap-4">
          <div>
            <h2 className="text-2xl font-bold text-gray-900 leading-tight">
              {itinerary.routeName || "Your Road Trip Adventure"}
            </h2>
            <p className="text-gray-500 mt-1 flex items-center gap-2 text-sm">
              <Calendar className="w-4 h-4" />
              {itinerary.summary || "Custom curated itinerary"}
            </p>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={onGenerateAlternative}
              className="px-4 py-2 bg-white border border-gray-200 hover:bg-gray-50 text-gray-700 rounded-full text-sm font-medium transition-colors flex items-center gap-2 shadow-sm"
            >
              <RefreshCw className="w-4 h-4" />
              Alternative Route
            </button>
            <button className="p-2 hover:bg-gray-100 rounded-full text-gray-500 transition-colors">
              <Share2 className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* View Tabs */}
        <div className="flex gap-6 mt-6 border-b border-gray-100 -mb-6">
          <button 
            onClick={() => setActiveTab('timeline')}
            className={`pb-3 text-sm font-semibold border-b-2 transition-colors ${activeTab === 'timeline' ? 'border-[#FF385C] text-[#FF385C]' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
          >
            Timeline
          </button>
          <button 
            onClick={() => setActiveTab('map')}
            className={`pb-3 text-sm font-semibold border-b-2 transition-colors ${activeTab === 'map' ? 'border-[#FF385C] text-[#FF385C]' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
          >
            Map View
          </button>
        </div>
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-y-auto bg-gray-50/50 p-4 lg:p-6 scroll-smooth custom-scrollbar">

        {activeTab === 'map' ? (
          <div className="h-full flex items-center justify-center text-gray-400 bg-gray-100 rounded-xl border border-dashed border-gray-300">
             <div className="text-center">
                <MapIcon className="w-12 h-12 mx-auto mb-2 opacity-20" />
                <p>Map visualization coming soon</p>
             </div>
          </div>
        ) : (
          <div className="max-w-3xl mx-auto space-y-8 pb-12">
            {dayPlans.map((day, index) => (
              <DayCard key={index} day={day} index={index} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

// --- Sub-Components ---

const DayCard: React.FC<{ day: DayPlan; index: number }> = ({ day, index }) => {
  const [isExpanded, setIsExpanded] = useState(true);

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden transition-all hover:shadow-md">
      {/* Day Header */}
      <div 
        onClick={() => setIsExpanded(!isExpanded)}
