// Integrated from real-keywords-collector/keywords.txt
const KEYWORD_MARKET_DATA = `
TARGET NICHE KEYWORDS (Use these for Search Validation):
- gay massage, sensual massage, erotic massage
- male massage therapist, male massage near me, gay massage therapist
- male body massage, massage male to male, male massage therapy
- gay friendly massage, gay spa massage, LGBTQ massage therapist
- massage for gay men, man on man massage, LGBTQ friendly massage
- gay deep tissue massage, gay couples massage, gay sports massage
- male to male massage therapy, gay Swedish massage
- professional male massage, male aromatherapy massage
- gay Thai massage, certified male massage therapist
`;

const extractJson = (text: string) => {
  try {
    // Clean markdown code blocks if present
    let cleanText = text.replace(/```json/g, '').replace(/```/g, '');

    // Attempt to find the first '{' and the last '}' to isolate JSON object
    const firstOpen = cleanText.indexOf('{');
    const lastClose = cleanText.lastIndexOf('}');

    if (firstOpen !== -1 && lastClose !== -1) {
      cleanText = cleanText.substring(firstOpen, lastClose + 1);
    }

    return JSON.parse(cleanText);
  } catch (e) {
    console.error("JSON Extraction failed", e);
    // Fallback simple regex
    try {
        const jsonMatch = text.match(/\{[\s\S]*\}|\[[\s\S]*\]/);
        if (!jsonMatch) return null;
        return JSON.parse(jsonMatch[0]);
    } catch (e2) {
        return null;
    }
  }
};

export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();
  const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

  const mandatoryStopsText = data.mandatoryStops
    .map(s => `${s.location}${s.arrivalDate ? ` (Arrive: ${s.arrivalDate})` : ''}`)
    .join(', ');

  const prompt = `
    TODAY'S DATE: ${today}
    ROLE: You are a specialized Logistics & Market Analyst for the male wellness sector.

    GOAL: Create a high-revenue road trip itinerary from ${data.origin} to ${data.destination}${data.destinationDate ? ` (Arrival by: ${data.destinationDate})` : ''}.

    CONSTRAINTS:
    - Max Drive: ${data.maxDriveHours} hours per leg.
    - Mandatory Stops: ${mandatoryStopsText || 'None'}.
    - Total Stops: Approx ${data.numberOfStops}.
    - Strategy: ${isAlternative ? 'Explore high-growth secondary markets (blue ocean strategy).' : 'Stick to established high-volume hubs (red ocean strategy).'}

    ${KEYWORD_MARKET_DATA}

    STRICT RULES FOR 'nightsToStay' (Classificação Final Definitiva):
    You MUST calculate 'nightsToStay' based strictly on the Demand Score (0-100) you assign:
    - **Score 90-100 (Platinum)**: 3 Nights.
    - **Score 75-89 (Gold)**: 2 Nights.
    - **Score 60-74 (Silver)**: 1 Night.
    - **Score < 60 (Bronze)**: 0 Nights (Day stop / Lunch only).
    - **Safety Override**: If search indicates active safety risks for LGBTQ+ travelers in the area, force 'nightsToStay' = 0 regardless of score.

    EXECUTION STEPS (Strict Data Validation):
    1. **Route Logic**: Plan a feasible driving route.
    2. **Market Validation (CRITICAL)**: Use Google Search to check demand in intermediate cities. 
       - *Query specific keywords* from the list above + city name (e.g., "male massage therapist Dallas").
       - Look for: Active directories, recent forum discussions, upcoming Pride events, or "circuit parties" in the next 3 months.
    3. **Evidence-Based Justification**: The 'profitabilityJustification' MUST cite specific findings (e.g., "Upcoming 'Market Days' festival", "High density of 5-star niche spas", "Trending on Google Trends").
    4. **Area Demand Clusters (ADC)**: Identify if a stop acts as a hub for smaller nearby towns.

    OUTPUT FORMAT (JSON):
    {
      "routeName": "Creative Route Name",
      "totalDistance": "e.g. 1200 miles",
      "totalDuration": "e.g. 18 hours drive",
      "summary": "Brief executive summary of why this route maximizes revenue based on search data.",
      "stops": [
        {
          "day": number,
          "city": "string",
          "activity": "Specific recommended marketing focus (e.g. 'Target Convention Center area')",
          "profitabilityJustification": "CITE EVIDENCE: Mention specific events, venue counts, or search trends found.",
          "demandScore": number (0-100),
          "trendVelocity": "🔥 (Exploding) | 📈 (Growing) | ➡️ (Stable) | 📉 (Declining)",
          "clusterInfo": { "anchorCity": "string", "clusterVolume": "string (High/Med/Low)" },
          "nightsToStay": number (MUST FOLLOW Classificação Final Rules),
          "travelTimeFromPrev": "e.g. 3h 15m",
          "travelToNext": "e.g. 4h 00m",
          "coordinates": { "lat": number, "lng": number }
        }
      ]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        // Corrected: maxOutputTokens is required when thinkingBudget is set.
        // Assuming ~4 tokens per word, 8k is generous for the output JSON.
        maxOutputTokens: 8192, 
        thinkingConfig: { thinkingBudget: 4096 }, // Adjusted to be within limits and allow response space
        tools: [{ googleSearch: {} }], 
      },
    });

    const result = extractJson(response.text) as Itinerary | null;
    if (!result) throw new Error("The AI response was invalid. Please try a simpler route or different drive limit.");

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const globalSources: GroundingSource[] = [];
    if (chunks) {
        chunks.forEach((chunk: any) => {
            if (chunk.web) {
                globalSources.push({
                    title: chunk.web.title || "Reference Source",
                    uri: chunk.web.uri
                });
            }
        });
    }
    result.sources = Array.from(new Map(globalSources.map(s => [s.uri, s])).values());

    // Precise Source Mapping: Try to match source content to the specific stop city
    result.stops = result.stops.map(stop => {
        const cityKeywords = stop.city.toLowerCase().split(',')[0].trim();
        const stopSources = globalSources.filter(s => 
            s.title.toLowerCase().includes(cityKeywords) || 
            s.uri.toLowerCase().includes(cityKeywords.replace(/\s/g, ''))
        );
        return {
            ...stop,
            stopSources: stopSources.length > 0 ? Array.from(new Map(stopSources.map(s => [s.uri, s])).values()) : undefined
        };
    });

    result.startDate = data.startDate;
    result.origin = data.origin;
    result.destination = data.destination;
    result.stops.sort((a, b) => a.day - b.day);

    return result;
  } catch (error: any) {
    console.error("Gemini Error:", error);
    throw new Error(error.message || "Route calculation failed. Check your API key and network.");
  }
};

